import { customElement, html } from "@umbraco-cms/backoffice/external/lit";
import { FormsSettingsElementBaseElement } from "./forms-settings-element-base.element.js";

const elementName = "forms-settings-autocomplete";

@customElement(elementName)
export class FormsSettingsAutocompleteElement extends FormsSettingsElementBaseElement {
  #autoCompleteOptions = [
    {
      label: this.localize.term("formSettings_autocompleteNone"),
      value: "None",
    },
    {
      label: this.localize.term("formSettings_autocompleteOn"),
      value: "On",
    },
    {
      label: this.localize.term("formSettings_autocompleteOff"),
      value: "Off",
    },
  ];

  render() {
    return html` <umb-property-layout
      alias="autocomplete"
      .label=${this.localize.term("formSettings_autocomplete")}
      .description=${this.localize.term("formSettings_autocompleteDescription")}
    >
      <div slot="editor" class="flex">
        <uui-label
          >${this.localize.term(
            "formSettings_autocompleteAttributeValue"
          )}</uui-label
        >
        <uui-radio-group
            .value=${this.form.autocompleteAttribute}
            @change=${(e) => this.onRadioChange(e, "autoCompleteAttribute")}
          >
            ${this.#autoCompleteOptions.map(
              (item) =>
                html`<uui-radio
                  name=${"autoCompleteAttribute"}
                  value=${item.value}
                  label=${item.label}
                ></uui-radio>`
            )}
          </uui-radio-group>
      </div>
    </umb-property-layout>`;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsSettingsAutocompleteElement;
  }
}
