import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import type { UmbCollectionDataSource } from "@umbraco-cms/backoffice/collection";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import type { RecordWorkflowAuditEntry } from "@umbraco-forms/generated";
import { RecordService } from "@umbraco-forms/generated";
import type {
  FormEntryAuditCollectionFilterModel,
  FormEntryWorkflowAuditCollectionModel,
} from "../../types.js";

export class FormsFormEntryWorkflowAuditCollectionServerDataSource
  implements UmbCollectionDataSource<FormEntryWorkflowAuditCollectionModel>
{
  #host: UmbControllerHost;

  constructor(host: UmbControllerHost) {
    this.#host = host;
  }

  async getCollection(filter: FormEntryAuditCollectionFilterModel) {
    const { data, error } = await tryExecuteAndNotify(
      this.#host,
      RecordService.getFormByFormIdRecordByRecordIdWorkflowAuditTrail(
        filter
      )
    );

    if (error) {
      return { error };
    }

    if (!data) {
      return { data: { items: [], total: 0 } };
    }

    const mappedItems: Array<FormEntryWorkflowAuditCollectionModel> = data.map(
      (item: RecordWorkflowAuditEntry) => {
        const record: FormEntryWorkflowAuditCollectionModel = {
          entityType: "forms-record-workflow-audit-entry",
          unique: item.id.toString(),
          workflowKey: item.workflowKey,
          name: item.name,
          typeName: item.typeName,
          executedOn: new Date(item.executedOn),
          executionStage: item.executionStage,
          result: item.result,
        };

        return record;
      }
    );

    return { data: { items: mappedItems, total: mappedItems.length } };
  }

  async executeWorkflow(formId: string, recordId: string, workflowId: string) {
    await tryExecuteAndNotify(
      this.#host,
      RecordService.postFormByFormIdRecordByRecordIdWorkflowByWorkflowIdRetry({
        formId,
        recordId,
        workflowId,
      })
    );
  }
}
