import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import type { UmbTreeAncestorsOfRequestArgs, UmbTreeChildrenOfRequestArgs, UmbTreeRootItemsRequestArgs} from "@umbraco-cms/backoffice/tree";
import { UmbTreeServerDataSourceBase } from "@umbraco-cms/backoffice/tree";
import type { FormTreeItemResponseModel } from "@umbraco-forms/generated";
import { FormService } from "@umbraco-forms/generated";
import { FORMS_FORM_FOLDER_ENTITY_TYPE, FORMS_FORM_ENTITY_TYPE, FORMS_FORM_ROOT_ENTITY_TYPE } from "../entities.js";
import type { FormTreeItemModel } from "./types.js";

/**
 * A data source for the Forms tree that fetches data from the server
 * @export
 * @class FormsFormTreeServerDataSource
 */
export class FormsFormTreeServerDataSource extends UmbTreeServerDataSourceBase<
  FormTreeItemResponseModel,
  FormTreeItemModel
> {
  constructor(host: UmbControllerHost) {
    super(host, {
      getRootItems,
      getChildrenOf,
      getAncestorsOf,
      mapper,
    });
  }
}

// eslint-disable-next-line local-rules/no-direct-api-import
const getRootItems = (args: UmbTreeRootItemsRequestArgs) => FormService.getTreeFormRoot({});

const getChildrenOf = (args: UmbTreeChildrenOfRequestArgs) => {
  if (args.parent.unique === null) {
    return getRootItems(args);
  }
  // eslint-disable-next-line local-rules/no-direct-api-import
  return FormService.getTreeFormChildrenByParentId({
    parentId: args.parent.unique!,
  });
};

const getAncestorsOf = (args: UmbTreeAncestorsOfRequestArgs) => {
	throw new Error('Not supported for the forms tree');
};


const mapper = (item: FormTreeItemResponseModel): FormTreeItemModel => {
  return {
    unique: item.id,
		parent: {
			unique: item.parent?.id || null,
			entityType: item.parent ? FORMS_FORM_FOLDER_ENTITY_TYPE : FORMS_FORM_ROOT_ENTITY_TYPE
		},
    name: item.name,
    path: item.path,
    entityType: item.isFolder ? FORMS_FORM_FOLDER_ENTITY_TYPE : FORMS_FORM_ENTITY_TYPE,
    isFolder: item.isFolder,
    hasChildren: item.hasChildren,
  };
};
