import { css, customElement, html, state, unsafeHTML, when } from "@umbraco-cms/backoffice/external/lit";
import { FormsAdvancedElementBaseElement } from "./forms-advanced-element-base.element.js";
import { UUISelectElement, UUITextareaElement } from "@umbraco-cms/backoffice/external/uui";
import { UMB_NOTIFICATION_CONTEXT } from "@umbraco-cms/backoffice/notification";
import { umbConfirmModal } from "@umbraco-cms/backoffice/modal";

const elementName = "forms-advanced-validation-rules";

@customElement(elementName)
export class FormsAdvancedValidationRulesElement extends FormsAdvancedElementBaseElement {

  #notificationContext?: typeof UMB_NOTIFICATION_CONTEXT.TYPE;

  constructor() {
    super();

    this.consumeContext(UMB_NOTIFICATION_CONTEXT, (instance) => {
      this.#notificationContext = instance;
    });
  }

  @state()
  _editIndex = -1;

  #isEditing() {
    return this._editIndex > -1;
  }

  #getRuleElement() {
    return this.#getTextAreaElement("rule");
  }

  #getErrorMessageElement() {
    return this.#getTextAreaElement("errorMessage");
  }

  #getFieldIdElement() {
    return this.shadowRoot?.getElementById("fieldId") as UUISelectElement;
  }

  #getTextAreaElement(id: string) {
    return this.shadowRoot?.getElementById(id) as UUITextareaElement;
  }

  #clearEditing() {
    this.#getRuleElement().value = "";
    this.#getErrorMessageElement().value = "";
    this.#getFieldIdElement().value = "";
    this._editIndex = -1;
  }

  #onEditClick(index: number) {
    this._editIndex = index;

    const validationRule = this.form.validationRules[this._editIndex];

    this.#getRuleElement().value = this.#formatJson(validationRule.rule);
    this.#getErrorMessageElement().value = validationRule.errorMessage;
  }

  #onSaveClick() {
    let rule = this.#getRuleElement().value.toString();
    const errorMessage = this.#getErrorMessageElement().value.toString();
    const fieldId = this.#getFieldIdElement().value.toString();

    try {
      rule = JSON.stringify(JSON.parse(rule));
    } catch (e) {
      const notification = {
        data: {
          headline: this.localize.term("formAdvanced_validationRulesErrorTitle"),
          message: this.localize.term("formAdvanced_validationRulesRuleErrorDescription"),
        }
      };
      this.#notificationContext?.peek("danger", notification);
      return;
    }

    if (errorMessage.trim().length === 0) {
      const notification = {
        data: {
          headline: this.localize.term("formAdvanced_validationRulesErrorTitle"),
          message: this.localize.term("formAdvanced_validationRulesMessageErrorDescription"),
        }
      };
      this.#notificationContext?.peek("danger", notification);
      return;
    }

    if (fieldId.length === 0) {
      const notification = {
        data: {
          headline: this.localize.term("formAdvanced_validationRulesErrorTitle"),
          message: this.localize.term("formAdvanced_validationRulesFieldErrorDescription"),
        }
      };
      this.#notificationContext?.peek("danger", notification);
      return;
    }

    const validationRules = structuredClone(this.form.validationRules);

    if (this.#isEditing()) {
      validationRules[this._editIndex].rule = rule;
      validationRules[this._editIndex].errorMessage = errorMessage;
      validationRules[this._editIndex].fieldId = fieldId;
    } else {
      validationRules.push({
        rule,
        errorMessage,
        fieldId
      });
    }

    this.setPropertyValue("validationRules", validationRules);

    this.#clearEditing();
  }

  #onCancelClick() {
    this.#clearEditing();
  }

  async #onDeleteClick(index: number) {
    await umbConfirmModal(this, {
      headline: this.localize.term("formAdvanced_deleteValidationRuleHeadline"),
      content: this.localize.term("formAdvanced_deleteValidationRuleMessage"),
      confirmLabel: this.localize.term("general_yes"),
      color: "danger",
    });

    const validationRules = structuredClone(this.form.validationRules);
    validationRules.splice(index, 1);
    this.setPropertyValue("validationRules", validationRules);
  }

  #formatJson(rule: string) {
    var json = JSON.parse(rule);
    return JSON.stringify(json, null, 2);
  }

  #getFieldDescription (fieldId: string) {
    const filteredFields = this.getAllFieldsForForm().filter(f => f.id === fieldId);
    if (filteredFields.length === 0) {
      return "";
    }

    const field = filteredFields[0];
    return field.caption + " (" + field.alias + ")";
  }

  render() {
    return html`<umb-property-layout
      alias="validationRules"
      .label=${this.localize.term("formAdvanced_validationRules")}
      .description=${this.localize.term("formAdvanced_validationRulesDescription")}
    >
      <div slot="editor">
        <div class="flex">
          <uui-table>
            <uui-table-head>
              <uui-table-head-cell>
                Rule
                <small>${unsafeHTML(this.localize.term("formAdvanced_validationRulesRuleDescription"))}</small>
              </uui-table-head-cell>
              <uui-table-head-cell>
                Message
                <small>${this.localize.term("formAdvanced_validationRulesErrorMessageDescription")}</small>
              </uui-table-head-cell>
              <uui-table-head-cell>
                Field
                <small>${this.localize.term("formAdvanced_validationRulesFieldDescription")}</small>
              </uui-table-head-cell>
              <uui-table-head-cell>
              </uui-table-head-cell>
            </uui-table-head>
              ${this.form.validationRules.map(
                (r, idx) => html` <uui-table-row>
                  <uui-table-cell><code>${this.#formatJson(r.rule)}</code></uui-table-cell>
                  <uui-table-cell>${r.errorMessage}</uui-table-cell>
                  <uui-table-cell>${this.#getFieldDescription(r.fieldId)}</uui-table-cell>
                  <uui-table-head-cell>
                    <uui-action-bar>
                      <uui-button
                        label="edit"
                        look="secondary"
                        color="default"
                        @click=${() => this.#onEditClick(idx)}
                      >
                        <uui-icon name="edit"></uui-icon>
                      </uui-button>
                      <uui-button
                        label=${this.localize.term("general_delete")}
                        look="secondary"
                        color="default"
                        @click=${() => this.#onDeleteClick(idx)}
                      >
                        <uui-icon name="delete"></uui-icon>
                      </uui-button>
                    </uui-action-bar>
                  </uui-table-head-cell>
                </uui-table-row>`
              )}

            <uui-table-row>
              <uui-table-cell>
                <uui-textarea id="rule" rows="8" class="json" placeholder="${this.localize.term("formAdvanced_validationRuleDefinition")}"></uui-textarea>
              </uui-table-cell>
              <uui-table-cell>
                <uui-textarea id="errorMessage" rows="8" placeholder="${this.localize.term("formAdvanced_validationRuleErrorMessage")}"></uui-textarea>
              </uui-table-cell>
              <uui-table-cell>
                <uui-select
                  id="fieldId"
                  .options=${
                    this.getAllFieldsForForm()
                      .map((f) => ({
                        name: this.localize.term(f.caption),
                        value: f.id,
                        selected: this._editIndex > -1 && f.id === this.form.validationRules[this._editIndex].fieldId
                      }))
                  }
                >
                </uui-select>
              </uui-table-cell>
              <uui-table-cell>
                <uui-action-bar>
                  <uui-button
                    label="add"
                    look="secondary"
                    color="default"
                    @click=${this.#onSaveClick}
                  >
                    <uui-icon
                      .name=${this.#isEditing() ? "icon-save" : "add"}
                    ></uui-icon>
                  </uui-button>
                  ${when(
                    this.#isEditing(),
                    () => html`<uui-button
                      label="add"
                      look="secondary"
                      color="default"
                      @click=${this.#onCancelClick}
                      ><uui-icon name="wrong"></uui-icon
                    ></uui-button>`
                  )}
                </uui-action-bar>
              </uui-table-cell>
            </uui-table-row>
          </uui-table>
        </div>
      </div>
    </umb-property-layout>`;
  }

  static styles = [
    css`
      uui-table-head-cell, uui-table-cell {
        vertical-align: top;
      }
      uui-table-head-cell small {
        display: block;
        font-weight: normal;
      }
      uui-table-cell code {
        background-color: var(--uui-color-surface-alt);
        border: solid 1px var(--uui-color-border-standalone);
        display: block;
        white-space: pre;
        font-family: monospace;
        font-size: 13px;
        padding: 4px;
        white-space: pre;
      }
      uui-textarea {
        width: 100%;
      }
      uui-textarea.json {
        font-family: monospace;
      }
    `,
  ];
}

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsAdvancedValidationRulesElement;
  }
}
