import type {
  UmbDataSourceResponse,
  UmbDetailDataSource,
} from "@umbraco-cms/backoffice/repository";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import type {
  WorkflowTypeWithSettings} from "@umbraco-forms/generated";
import {
  WorkflowTypeService
} from "@umbraco-forms/generated";

export class FormsWorkflowTypeDetailServerDataSource
  implements UmbDetailDataSource<WorkflowTypeWithSettings>
{
  #host: UmbControllerHost;

  constructor(host: UmbControllerHost) {
    this.#host = host;
  }

  async read(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    const { data, error } = await tryExecuteAndNotify(
      this.#host,
      WorkflowTypeService.getWorkflowTypeById({
        id: unique,
      })
    );

    if (error || !data) {
      return { error };
    }

    return { data: data as WorkflowTypeWithSettings };
  }

  createScaffold(
    preset?: Partial<WorkflowTypeWithSettings> | undefined
  ): Promise<UmbDataSourceResponse<WorkflowTypeWithSettings>> {
    throw new Error("Method not implemented.");
  }

  create(
    data: WorkflowTypeWithSettings,
    parentUnique: string | null
  ): Promise<UmbDataSourceResponse<WorkflowTypeWithSettings>> {
    throw new Error("Method not implemented.");
  }

  update(
    data: WorkflowTypeWithSettings
  ): Promise<UmbDataSourceResponse<WorkflowTypeWithSettings>> {
    throw new Error("Method not implemented.");
  }

  delete(unique: string): Promise<UmbDataSourceResponse<unknown>> {
    throw new Error("Method not implemented.");
  }
}
