import { customElement, html } from "@umbraco-cms/backoffice/external/lit";
import { FormsFieldPreviewBaseElement } from './field-preview-base.element.js';

const elementName = "forms-field-preview-fileupload"
@customElement(elementName)
export class FormsFieldPreviewFileUpload extends FormsFieldPreviewBaseElement{
  render() {
    return html`<input disabled type="file" />
    <p>
      <strong>Current file(s):</strong>
    </p>`;
  }
}

export default FormsFieldPreviewFileUpload;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFieldPreviewFileUpload;
  }
}
