import { UmbEntityActionBase } from '@umbraco-cms/backoffice/entity-action';
import { UMB_MODAL_MANAGER_CONTEXT } from '@umbraco-cms/backoffice/modal';
import { FORMS_FORM_CREATE_OPTIONS_MODAL } from './modal/index.js';

export class FormsCreateFormEntityAction extends UmbEntityActionBase<never> {
	async execute() {
		const modalManager = await this.getContext(UMB_MODAL_MANAGER_CONTEXT);
		const modalContext = modalManager.open(this, FORMS_FORM_CREATE_OPTIONS_MODAL, {
			data: {
				parent: {
					entityType: this.args.entityType,
					unique: this.args.unique,
				},
			},
		});

		await modalContext.onSubmit().catch(() => undefined);
	}
}
