import { customElement, html } from "@umbraco-cms/backoffice/external/lit";
import { FormsFieldPreviewBaseElement } from './field-preview-base.element.js';

const elementName = "forms-field-preview-titleanddescription"
@customElement(elementName)
export class FormsFieldPreviewTitleAndDescription extends FormsFieldPreviewBaseElement{
  render() {
    return html`
    <h3>
      ${this.getSettingValue("Headline") ?? "Sample headline"}
    </h3>
    <div>
      ${this.getSettingValue("BodyText") ?? "Sample body text"}
    </div>`;
  }
}

export default FormsFieldPreviewTitleAndDescription;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFieldPreviewTitleAndDescription;
  }
}
