import type { UmbPropertyValueData } from "@umbraco-cms/backoffice/property";
import type { Setting } from "@umbraco-forms/generated";
import type { UmbPropertyEditorConfig } from "@umbraco-cms/backoffice/property-editor";
import type { FormsSettingValueConverterApi } from './setting-value-converter.interface.js';

export class FormsMultipleTextSettingValueConverter implements FormsSettingValueConverterApi  {
  async getSettingValueForEditor(setting: Setting, alias: string, value: string) {
    let editorValue: string[] = [];
    if (!value) {
      editorValue = [];
    } else {
      editorValue = value.split(",");
    }

    return Promise.resolve(editorValue);
  }

  async getSettingValueForPersistence(setting: Setting, valueData: UmbPropertyValueData) {
    const persistedValue = (valueData.value as Array<string>).join(",");
    return Promise.resolve(persistedValue);
  }

  async getSettingPropertyConfig(setting: Setting, alias: string, values: UmbPropertyValueData[]) {
    const config: UmbPropertyEditorConfig = [];
    return Promise.resolve(config);
  }

  destroy() {
  }
}
