import { customElement, html } from "@umbraco-cms/backoffice/external/lit";
import { FormsFieldPreviewBaseElement } from './field-preview-base.element.js';

const elementName = "forms-field-preview-password"
@customElement(elementName)
export class FormsFieldPreviewPassword extends FormsFieldPreviewBaseElement{
  render() {
    return html`<input type="password" readonly disabled tabindex="-1" placeholder=${this.getSettingValue("Placeholder")} />`;
  }
}

export default FormsFieldPreviewPassword;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFieldPreviewPassword;
  }
}
