import { UmbId } from '@umbraco-cms/backoffice/id';
import type { UmbDetailDataSource } from '@umbraco-cms/backoffice/repository';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import { tryExecuteAndNotify } from '@umbraco-cms/backoffice/resources';
import { FormFieldIndication, FormService, MultiPageNavigationOption, type FormDesign } from '@umbraco-forms/generated';

/**
 * A data source for the Form that fetches data from the server
 * @export
 * @class FormsFormDetailServerDataSource
 * @implements {RepositoryDetailDataSource}
 */
export class FormsFormDetailServerDataSource implements UmbDetailDataSource<FormDesign> {
	#host: UmbControllerHost;

	constructor(host: UmbControllerHost) {
		this.#host = host;
	}

	/**
	 * Creates a new Form scaffold
	 * @param {(string | null)} parentUnique
	 * @return { FormDetailModel }
	 * @memberof FormsFormDetailServerDataSource
	 */
	async createScaffold(preset: Partial<FormDesign> = {}) {
		const id = UmbId.new();
		const data: FormDesign = {
			entityType: 'form',
			unique: id,
			id: id,
			created: new Date().toJSON(),
			updated: new Date().toJSON(),
			messageOnSubmitIsHtml: false,
			displayDefaultFields: true,
			daysToRetainApprovedRecordsFor: 0,
			daysToRetainRejectedRecordsFor: 0,
			daysToRetainSubmittedRecordsFor: 0,
			selectedDisplayFields: [],
			nodeId: 0,
			name: '',
			path: '',
			formWorkflows: {
				onSubmit: [],
				onApprove: [],
				onReject: [],
			},
			pages: [],
			fieldIndicationType: FormFieldIndication.MARK_MANDATORY_FIELDS,
			indicator: '*',
			showValidationSummary: false,
			hideFieldValidation: false,
			requiredErrorMessage: '',
			invalidErrorMessage: '',
			messageOnSubmit: '',
			manualApproval: false,
			storeRecordsLocally: false,
			autocompleteAttribute: '',
			disableDefaultStylesheet: false,
			submitLabel: '',
			nextLabel: '',
			prevLabel: '',
			showPagingOnMultiPageForms: MultiPageNavigationOption.NONE,
			pagingDetailsFormat: '',
			pageCaptionFormat: '',
			showSummaryPageOnMultiPageForms: false,
			validationRules: []
		};

		return { data };
	}

	/**
	 * Fetches a Form with the given id from the server
	 * @param {string} unique
	 * @return {FormDesign}
	 * @memberof FormsFormDetailServerDataSource
	 */
	async read(unique: string) {
		if (!unique) throw new Error('Unique is missing');

		const { data, error } = await tryExecuteAndNotify(this.#host, FormService.getFormById({ id: unique }));

		if (error || !data) {
			return { error };
		}

		// TODO => this should be mapped, not cast
		return { data: data as FormDesign };
	}

	/**
	 * Inserts a new Form on the server
	 * @param {FormDetailModel} form
	 * @return {*}
	 * @memberof FormsFormDetailServerDataSource
	 */
	async create(form: FormDesign) {
		if (!form) throw new Error('Form is missing');
		if (!form.unique) throw new Error('Form unique is missing');

		const { error: createError } = await tryExecuteAndNotify(
			this.#host,
			FormService.postForm({
				requestBody: form
			}),
		);

		if (createError) {
			return { error: createError };
		}

		// We have to fetch the data type again. The server can have modified the data after creation
		return this.read(form.unique);
	}

	/**
	 * Updates a Form on the server
	 * @param {FormDetailModel} Form
	 * @return {*}
	 * @memberof FormsFormDetailServerDataSource
	 */
	async update(form: FormDesign) {
		if (!form.unique) throw new Error('Unique is missing');

		const { error } = await tryExecuteAndNotify(
			this.#host,
			FormService.putFormById({
				id: form.id,
				requestBody: form
			}),
		);

		if (error) {
			return { error };
		}

		// We have to fetch the form again. The server can have modified the data after update
		return this.read(form.unique);
	}

	/**
	 * Deletes a Form on the server
	 * @param {string} unique
	 * @return {*}
	 * @memberof FormsFormDetailServerDataSource
	 */
	async delete(unique: string) {
		if (!unique) throw new Error('Unique is missing');

		return tryExecuteAndNotify(
			this.#host,
			FormService.deleteFormById({
				id: unique,
			}),
		);
	}
}
