import type { UmbConditionControllerArguments, UmbExtensionCondition } from '@umbraco-cms/backoffice/extension-api';
import { UmbConditionBase } from '@umbraco-cms/backoffice/extension-registry';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import { FORMS_FORM_WORKSPACE_CONTEXT } from '../workspace/form-workspace.context-token.js';
import type { FormSettingsConditionConfig } from './form-settings-condition.config.js';

export class FormsFormSettingsCondition
	extends UmbConditionBase<FormSettingsConditionConfig>
	implements UmbExtensionCondition
{
	constructor(
		host: UmbControllerHost,
		args: UmbConditionControllerArguments<FormSettingsConditionConfig>,
	) {
		super(host, args);

		this.consumeContext(FORMS_FORM_WORKSPACE_CONTEXT, (context) => {
			const form = context.getData();
			this.permitted = form ? this.config.match(form) : false;
		});
	}
}

export default FormsFormSettingsCondition;