import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import type { UmbApi } from '@umbraco-cms/backoffice/extension-api';
import { UmbTreeRepositoryBase } from '@umbraco-cms/backoffice/tree';
import { FORMS_SECURITY_ROOT_ENTITY_TYPE } from '../entities.js';
import { FormsSecurityTreeServerDataSource } from './security-tree.server.data-source.js';
import type { SecurityTreeItemModel, SecurityTreeRootModel } from './types.js';
import { FORMS_SECURITY_TREE_STORE_CONTEXT } from './security-tree.store.js';

export class FormsSecurityTreeRepository
	extends UmbTreeRepositoryBase<SecurityTreeItemModel, SecurityTreeRootModel>
	implements UmbApi
{
	constructor(host: UmbControllerHost) {
		super(host, FormsSecurityTreeServerDataSource, FORMS_SECURITY_TREE_STORE_CONTEXT);
	}

	async requestTreeRoot() {
		const data: SecurityTreeRootModel = {
			unique: null,
			entityType: FORMS_SECURITY_ROOT_ENTITY_TYPE,
			name: 'Security',
			hasChildren: true,
			isFolder: true,
		};

		return { data };
	}
}
