import { customElement, html } from "@umbraco-cms/backoffice/external/lit";
import { FormsFieldPreviewBaseElement } from './field-preview-base.element.js';

const elementName = "forms-field-preview-datepicker"
@customElement(elementName)
export class FormsFieldPreviewDatePicker extends FormsFieldPreviewBaseElement{
  render() {
    return html`<input type="text"
    autocomplete="off"
    disabled
    readonly
    placeholder="${this.getSettingValue("Placeholder")}"/>
    <button class="btn" disabled>
      <uui-icon name="icon-calendar"></uui-icon>
    </button>`;
  }
}

export default FormsFieldPreviewDatePicker;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFieldPreviewDatePicker;
  }
}
