import { customElement, html } from "@umbraco-cms/backoffice/external/lit";
import { UmbModalBaseElement } from "@umbraco-cms/backoffice/modal";
import type { WorkflowTypeWithSettings } from "@umbraco-forms/generated";
import type {
  FormsChooseWorkflowTypeModalData,
  FormsChooseWorkflowTypeModalValue,
} from "../token/form-choose-workflow-type-modal.token.js";
import { FormsWorkflowTypeCollectionRepository } from "../../section/provider-types/workflow-types/repository/collection/workflow-type-collection.repository.js";

const elementName = "form-choose-workflow-type-modal";

@customElement(elementName)
export class FormsChooseWorkflowTypeModalElement extends UmbModalBaseElement<
  FormsChooseWorkflowTypeModalData,
  FormsChooseWorkflowTypeModalValue
> {
  #workflowTypes: Array<WorkflowTypeWithSettings> = [];

  constructor() {
    super();
    this.#initialize();
  }

  async #initialize() {
    const repository = new FormsWorkflowTypeCollectionRepository(this);
    const { data } = await repository.requestCollection();
    this.#workflowTypes = data?.items || [];
    this.requestUpdate();
  }

  #onSelectWorkflowTypeClick(selectedValue: WorkflowTypeWithSettings) {
    this.modalContext?.updateValue({ selectedValue });
    this.modalContext?.submit();
  }

  render() {
    return html`<umb-body-layout headline=${this.localize.term("formWorkflows_chooseWorkflowType")}>
      <uui-box>
        <uui-ref-list>
          ${this.#workflowTypes.map(
            (workflowType) =>
              html`<umb-ref-item
                selectable
                .title=${workflowType.name}
                .name=${workflowType.name}
                .detail=${workflowType.description}
                .icon=${workflowType.icon}
                @click=${() => this.#onSelectWorkflowTypeClick(workflowType)}
              >
              </umb-ref-item>`
          )}
        </uui-ref-list>
      </uui-box>
      <div slot="actions">
        <uui-button
          label=${this.localize.term("general_close")}
          @click="${this._rejectModal}"
        ></uui-button>
      </div>
    </umb-body-layout>`;
  }
}

export default FormsChooseWorkflowTypeModalElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsChooseWorkflowTypeModalElement;
  }
}
