import type {
  UmbDataSourceResponse,
  UmbDetailDataSource,
} from "@umbraco-cms/backoffice/repository";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import type { PreValueSourceTypeWithSettings } from "@umbraco-forms/generated";
import { DataSourceTypeService } from "@umbraco-forms/generated";

export class FormsDataSourceTypeDetailServerDataSource
  implements UmbDetailDataSource<PreValueSourceTypeWithSettings>
{
  #host: UmbControllerHost;

  constructor(host: UmbControllerHost) {
    this.#host = host;
  }

  async read(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    const { data, error } = await tryExecuteAndNotify(
      this.#host,
      DataSourceTypeService.getDataSourceTypeById({
        id: unique,
      })
    );

    if (error || !data) {
      return { error };
    }

    return { data: data as PreValueSourceTypeWithSettings };
  }

  createScaffold(
    preset?: Partial<PreValueSourceTypeWithSettings> | undefined
  ): Promise<UmbDataSourceResponse<PreValueSourceTypeWithSettings>> {
    throw new Error("Method not implemented.");
  }

  create(
    data: PreValueSourceTypeWithSettings,
    parentUnique: string | null
  ): Promise<UmbDataSourceResponse<PreValueSourceTypeWithSettings>> {
    throw new Error("Method not implemented.");
  }

  update(
    data: PreValueSourceTypeWithSettings
  ): Promise<UmbDataSourceResponse<PreValueSourceTypeWithSettings>> {
    throw new Error("Method not implemented.");
  }

  delete(unique: string): Promise<UmbDataSourceResponse<unknown>> {
    throw new Error("Method not implemented.");
  }
}
