import { customElement, html } from "@umbraco-cms/backoffice/external/lit";
import { FormsSettingsElementBaseElement } from "./forms-settings-element-base.element.js";
import { MultiPageNavigationOption } from "@umbraco-forms/generated";

const elementName = "forms-settings-multi-page";

@customElement(elementName)
export class FormsSettingsMultiPageElement extends FormsSettingsElementBaseElement {

  #getPagingOptions(selectedValue: MultiPageNavigationOption) {
    return [{
      name: this.localize.term("formSettings_multiPageFormsNavigationNone"),
      value: MultiPageNavigationOption.NONE.toString(),
      selected: selectedValue === MultiPageNavigationOption.NONE.toString(),
    },
    {
      name: this.localize.term("formSettings_multiPageFormsNavigationShowOnTop"),
      value: MultiPageNavigationOption.SHOW_AT_TOP.toString(),
      selected: selectedValue === MultiPageNavigationOption.SHOW_AT_TOP.toString(),
    },
    {
      name: this.localize.term("formSettings_multiPageFormsNavigationShowOnBottom"),
      value: MultiPageNavigationOption.SHOW_AT_BOTTOM.toString(),
      selected: selectedValue === MultiPageNavigationOption.SHOW_AT_BOTTOM.toString(),
    },
    {
      name: this.localize.term("formSettings_multiPageFormsNavigationShowOnTopAndBottom"),
      value: MultiPageNavigationOption.SHOW_AT_TOP.toString() + ", " + MultiPageNavigationOption.SHOW_AT_BOTTOM.toString(),
      selected: selectedValue === MultiPageNavigationOption.SHOW_AT_TOP.toString() + ", " + MultiPageNavigationOption.SHOW_AT_BOTTOM.toString(),
    }];
  };

  render() {
    return html`<umb-property-layout
      alias="multipage"
      .label=${this.localize.term("formSettings_multiPageForms")}
      .description=${this.localize.term("formSettings_multiPageFormsDescription")}
    >
      <div slot="editor">
        <div class="flex">
          <uui-label
            >${this.localize.term(
              "formSettings_multiPageFormsShowPaging"
            )}</uui-label
          >
          <uui-select
            id="multiPageFormsShowPaging"
            .options=${this.#getPagingOptions(this.form.showPagingOnMultiPageForms)}
            @change=${(e) => this.onSelectChange(e, "showPagingOnMultiPageForms")}
          >
          </uui-select>
        </div>
        <div class="flex">
          <uui-label
            >${this.localize.term(
              "formSettings_pagingDetailsFormat"
            )}</uui-label
          >
          <uui-input
            type="text"
            .label=${this.localize.term("formSettings_pagingDetailsFormat")}
            .value=${this.form?.pagingDetailsFormat}
            @change=${(e) => this.onInputChange(e, "pagingDetailsFormat")}
          ></uui-input>
        </div>
        <div class="flex">
          <uui-label
            >${this.localize.term(
              "formSettings_pageCaptionFormat"
            )}</uui-label
          >
          <uui-input
            type="text"
            .label=${this.localize.term("formSettings_pageCaptionFormat")}
            .value=${this.form?.pageCaptionFormat}
            @change=${(e) => this.onInputChange(e, "pageCaptionFormat")}
          ></uui-input>
        </div>
        ${this.renderToggle(
          this.form?.showSummaryPageOnMultiPageForms,
          "showSummaryPageOnMultiPageForms",
          "formSettings_multiPageFormsShowSummaryPage"
        )}
        <div class="flex">
          <uui-label
            >${this.localize.term(
              "formSettings_summaryLabel"
            )}</uui-label
          >
          <uui-input
            type="text"
            .label=${this.localize.term("formSettings_summaryLabel")}
            .value=${this.form?.summaryLabel}
            @change=${(e) => this.onInputChange(e, "summaryLabel")}
          ></uui-input>
        </div>
      </div>
    </umb-property-layout>`;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsSettingsMultiPageElement;
  }
}
