import type { UmbPropertyValueData } from "@umbraco-cms/backoffice/property";
import { MediaService as FormsMediaService } from "@umbraco-forms/generated";
import type { Setting } from "@umbraco-forms/generated";
import type { UmbPropertyEditorConfig } from "@umbraco-cms/backoffice/property-editor";
import { tryExecute } from "@umbraco-cms/backoffice/resources";
import { MediaService as CmsMediaService } from "@umbraco-cms/backoffice/external/backend-api";
import type { FormsSettingValueConverterApi } from './setting-value-converter.interface.js';

export class FormsMediaEntityPickerSettingValueConverter
  implements FormsSettingValueConverterApi
{
  async getSettingValueForEditor(
    setting: Setting,
    alias: string,
    value: string
  ) {
    // Translate from the path to the media key.
    if (value) {
      const { data } = await tryExecute(
        FormsMediaService.getMediaByPath({ path: encodeURIComponent(value) })
      );
      if (data) {
        return Promise.resolve(data.id);
      }
    }

    return Promise.resolve("");
  }

  async getSettingValueForPersistence(setting: Setting, valueData: UmbPropertyValueData) {
    const id = valueData.value as string;

    if (id) {
      // Translate from the media key to the path.
      const { data } = await tryExecute(
        CmsMediaService.getMediaUrls({ id: [id] })
      );

      const url = data?.[0]?.urlInfos?.[0].url;
      if (!url) return Promise.resolve("");
      
      const path = new URL(url).pathname;
      return Promise.resolve(path);      
    }

    return Promise.resolve("");
  }

  async getSettingPropertyConfig(
    setting: Setting,
    alias: string,
    values: UmbPropertyValueData[]
  ) {
    const config: UmbPropertyEditorConfig = [];
    config.push({
      alias: "validationLimit",
      value: {
        min: 1,
        max: 1,
      },
    });
    return Promise.resolve(config);
  }

  destroy() {}
}
