import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { UmbDetailRepositoryBase } from "@umbraco-cms/backoffice/repository";
import { PrevalueSourceService, type FieldPreValueSource } from "@umbraco-forms/generated";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import {
  FORMS_PREVALUESOURCE_DETAIL_STORE_CONTEXT,
} from "./prevaluesource-detail.store.js";
import { FormsPrevalueSourceDetailServerDataSource } from "./prevaluesource-detail.server.data-source.js";

export class FormsPrevalueSourceDetailRepository extends UmbDetailRepositoryBase<FieldPreValueSource> {
  constructor(host: UmbControllerHost) {
    super(
      host,
      FormsPrevalueSourceDetailServerDataSource,
      FORMS_PREVALUESOURCE_DETAIL_STORE_CONTEXT
    );
  }

	async requestPrevalueSourceScaffold() {
		const { data, error } = await tryExecuteAndNotify(this._host, PrevalueSourceService.getPrevalueSourceScaffold());

		if (error || !data) {
			return { error };
		}

		return { data };
	}

	async requestPrevalues(id: string, formId?: string, fieldId?: string) {
		const { data, error } = await tryExecuteAndNotify(this._host, PrevalueSourceService.getPrevalueSourceByIdValues({ id, formId, fieldId }));

		if (error || !data) {
			return { error };
		}

		return { data };
	}
}
