import type { UmbCollectionRepository } from '@umbraco-cms/backoffice/collection';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import type { FormEntryAuditCollectionFilterModel } from '../../types.js';
import { FormsFormEntryRecordAuditCollectionServerDataSource } from './entry-record-audit-collection.server.data-source.js';

export class FormsFormEntryRecordAuditCollectionRepository implements UmbCollectionRepository {
	#collectionSource: FormsFormEntryRecordAuditCollectionServerDataSource;

	constructor(host: UmbControllerHost) {
		this.#collectionSource = new FormsFormEntryRecordAuditCollectionServerDataSource(host);
	}

	async requestCollection(filter: FormEntryAuditCollectionFilterModel = {
		formId: '',
		recordId: ''
	}) {
		return this.#collectionSource.getCollection(filter);
	}

	destroy(): void {}
}

export default FormsFormEntryRecordAuditCollectionRepository;
