import type { UmbCollectionRepository } from '@umbraco-cms/backoffice/collection';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import { FormsFieldTypeCollectionServerDataSource } from './field-type-collection.server.data-source.js';

export class FormsFieldTypeCollectionRepository implements UmbCollectionRepository {
	#collectionSource: FormsFieldTypeCollectionServerDataSource;

	constructor(host: UmbControllerHost) {
		this.#collectionSource = new FormsFieldTypeCollectionServerDataSource(host);
	}

	async requestCollection() {
		return this.#collectionSource.getCollection();
	}

	destroy(): void {}
}

export default FormsFieldTypeCollectionRepository;
