import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { UmbDetailRepositoryBase } from "@umbraco-cms/backoffice/repository";
import type { FormSecurityForUser} from "@umbraco-forms/generated";
import { SecurityService } from "@umbraco-forms/generated";
import {
  FORMS_SECURITY_USER_DETAIL_STORE_CONTEXT,
} from "./security-user-detail.store.js";
import { FormsSecurityUserDetailServerDataSource } from "./security-user-detail.server.data-source.js";

export class FormsSecurityUserDetailRepository extends UmbDetailRepositoryBase<FormSecurityForUser> {
  constructor(host: UmbControllerHost) {
    super(
      host,
      FormsSecurityUserDetailServerDataSource,
      FORMS_SECURITY_USER_DETAIL_STORE_CONTEXT
    );
  }

  async requestUsersToAssign() {
    return await SecurityService.getSecurityUserUsersToAssign();
  }
}
