import { customElement, html, repeat } from "@umbraco-cms/backoffice/external/lit";
import { FormsFieldPreviewBaseElement } from './field-preview-base.element.js';

const elementName = "forms-field-preview-dropdown"
@customElement(elementName)
export class FormsFieldPreviewDropdown extends FormsFieldPreviewBaseElement{
  render() {
    return html`<select tabindex="-1" style="opacity: 0.5; min-width: 300px">
      <option>${this.getSettingValue("SelectPrompt")}</option>
      ${repeat(this.prevalues,
        (pv) => html`<option>${pv.caption || pv.value}</option>`)}
    </select>`;
  }
}

export default FormsFieldPreviewDropdown;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFieldPreviewDropdown;
  }
}
