import type { UmbPropertyValueData } from "@umbraco-cms/backoffice/property";
import type { Setting } from "@umbraco-forms/generated";
import { FieldTypeService } from "@umbraco-forms/generated";
import type { UmbPropertyEditorConfig } from "@umbraco-cms/backoffice/property-editor";
import { tryExecute } from "@umbraco-cms/backoffice/resources";
import type { FormsSettingValueConverterApi } from './setting-value-converter.interface.js';

export class FormsRichTextSettingValueConverter implements FormsSettingValueConverterApi  {

  async getSettingValueForEditor(setting: Setting, alias: string, value: string) {
    const editorValue = { markup: value };
    return Promise.resolve(editorValue);
  }

  async getSettingValueForPersistence(setting: Setting, valueData: UmbPropertyValueData) {
    const persistedValue = valueData.value ? valueData.value["markup"] : "";
    return Promise.resolve(persistedValue);
  }

  async getSettingPropertyConfig(setting: Setting, alias: string, values: UmbPropertyValueData[]) {
    const config: UmbPropertyEditorConfig = [];

    // Config comes from the configured rich text data type.
    const { data } = await tryExecute(
      FieldTypeService.getFieldTypeRichtextDatatype(),
    );

    config.push({
      alias: "maxImageSize",
      value: data.configurationData.maxImageSize,
    });
    config.push({
      alias: "toolbar",
      value: data.configurationData.toolbar,
    });

    // - Tiptap
    if (data.configurationData.extensions) {
      config.push({
        alias: "extensions",
        value: data.configurationData.extensions,
      });
    }

    // - TinyMCE
    if (data.configurationData.mode) {
      config.push({
        alias: "mode",
        value: data.configurationData.mode,
      });
      if (data.configurationData.mode) {
        config.push({
          alias: "stylesheets",
          value: data.configurationData.stylesheets,
        });
      }
    }

    return config;
  }

  destroy() {
  }
}

