import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import type { UmbApi } from '@umbraco-cms/backoffice/extension-api';
import { UmbTreeRepositoryBase } from '@umbraco-cms/backoffice/tree';
import { FORMS_FORM_ROOT_ENTITY_TYPE } from '../entities.js';
import { FormsFormTreeServerDataSource } from './forms-tree.server.data-source.js';
import type { FormTreeItemModel, FormTreeRootModel } from './types.js';
import { FORMS_FORM_TREE_STORE_CONTEXT } from './forms-tree.store.js';

export class FormsFormTreeRepository
	extends UmbTreeRepositoryBase<FormTreeItemModel, FormTreeRootModel>
	implements UmbApi
{
	constructor(host: UmbControllerHost) {
		super(host, FormsFormTreeServerDataSource, FORMS_FORM_TREE_STORE_CONTEXT);
	}

	async requestTreeRoot() {
		const data: FormTreeRootModel = {
			unique: null,
			entityType: FORMS_FORM_ROOT_ENTITY_TYPE,
			name: 'Forms',
			hasChildren: true,
			isFolder: true,
		};

		return { data };
	}
}
