import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { UmbDetailRepositoryBase } from "@umbraco-cms/backoffice/repository";
import type { FieldTypeWithSettings} from "@umbraco-forms/generated";
import { FieldTypeService } from "@umbraco-forms/generated";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import { FormsFieldTypeDetailServerDataSource } from "./field-type-detail.server.data-source.js";
import { FORMS_FIELD_TYPE_DETAIL_STORE_CONTEXT } from "./field-type-detail.store.js";

export class FormsFieldTypeDetailRepository extends UmbDetailRepositoryBase<FieldTypeWithSettings> {
	constructor(host: UmbControllerHost) {
		super(
			host,
			FormsFieldTypeDetailServerDataSource,
			FORMS_FIELD_TYPE_DETAIL_STORE_CONTEXT
		);
	}

	async requestValidationPatterns() {
		const { data, error } = await tryExecuteAndNotify(this._host, FieldTypeService.getFieldTypeValidationPattern());

		if (error || !data) {
			return { error };
		}

		return { data };
	}
}
