import { UmbItemServerDataSourceBase } from '@umbraco-cms/backoffice/repository';
import { FormService, type FormItemResponseModel } from "@umbraco-forms/generated";
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import type { FormItemModel } from './types.js';

export class FormsFormItemServerDataSource extends UmbItemServerDataSourceBase<
	FormItemResponseModel,
	FormItemModel
> {
	constructor(host: UmbControllerHost) {
		super(host, {
			getItems,
			mapper,
		});
	}
}

/* eslint-disable local-rules/no-direct-api-import */
const getItems = (uniques: Array<string>) => FormService.getItemForm({ id: uniques });

const mapper = (item: FormItemResponseModel): FormItemModel => {
	return {
		unique: item.id,
		name: item.name
	};
};
