import {
  customElement,
  html,
  queryAll,
  state,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbModalBaseElement } from "@umbraco-cms/backoffice/modal";
import type { FormsExportEntriesModalData } from "@umbraco-forms/modals";
import { ExportService } from "@umbraco-forms/generated";
import type { RecordExportFilter, ExportType } from "@umbraco-forms/generated";
import type { UmbRefItemElement } from "@umbraco-cms/backoffice/components";
import { firstValueFrom } from "@umbraco-cms/backoffice/external/rxjs";
import { UMB_NOTIFICATION_CONTEXT } from "@umbraco-cms/backoffice/notification";
import { blobDownload } from "@umbraco-cms/backoffice/utils";
import { FORMS_FORM_ENTRY_COLLECTION_CONTEXT } from "../../section/forms/entries/collection/form-entry-collection.context-token.js";

const elementName = "form-export-entries-modal";

@customElement(elementName)
export class FormsExportEntriesModalElement extends UmbModalBaseElement<
  FormsExportEntriesModalData,
  FormsExportEntriesModalElement
> {
  @state()
  private _exportTypes: Array<ExportType> = [];

  @queryAll("umb-ref-item")
  private _refItems?: Array<UmbRefItemElement>;

  #selectedExportType?: string;
  #exporting = false;

  async connectedCallback() {
    super.connectedCallback();

    this._exportTypes = await ExportService.getExportTypes({
      formId: this.data?.unique,
    });
  }

  #handleExportTypeSelection(e: CustomEvent) {
    const target = e.target as UmbRefItemElement;

    if (target.id === this.#selectedExportType) return;

    this._refItems?.forEach((ref) => {
      if (ref.id !== target.id) {
        ref.selected = false;
      }
    });

    this.#selectedExportType = this._exportTypes.find(
      (x) => x.alias === target.id
    )?.id;
  }

  async #export() {
    if (this.#exporting || !this.#selectedExportType) return;

    this.#exporting = true;

    // filter values are available on context. nice!
    const collectionContext = await this.getContext(
      FORMS_FORM_ENTRY_COLLECTION_CONTEXT
    );

    const filter = {
      ...(await firstValueFrom(collectionContext.filter)),
      ...{ exportType: this.#selectedExportType, formId: this.data?.unique },
    };

    // TODO => Check if we need to do server time offset to the date we are displaying
    // var serverTimeNeedsOffsetting = utilityService.serverTimeNeedsOffsetting();
    // if (serverTimeNeedsOffsetting) {
    //   // Use the localOffset to correct the server times with the client browser's offset
    //   filter.localTimeOffset = new Date().getTimezoneOffset();
    // }

    const { formId, fileName } = await ExportService.postExport({
      formId: this.data?.unique,
      requestBody: filter as RecordExportFilter,
    });

    const blob = await ExportService.getExport({ fileName, formId });
    blobDownload(blob, fileName, "text/xml");

    this.#exporting = false;

    const notificationContext = await this.getContext(UMB_NOTIFICATION_CONTEXT);
    notificationContext.peek("positive", {
      data: { message: "Export complete." },
    });

    this._submitModal();
  }

  render() {
    return html`<umb-body-layout
      .headline=${this.localize.term("formEntries_export")}
    >
      <uui-box>
        <umb-property-layout
          orientation="vertical"
          .label=${this.localize.term("formEntries_chooseExportFormat")}
        >
          <div slot="editor">
            <uui-ref-list>
              ${this._exportTypes.map(
                (exportType) =>
                  html`<umb-ref-item
                    selectable
                    id=${exportType.alias}
                    .name=${this.localize.term(
                      `formProviderExportTypes_${exportType.alias}`,
                      exportType.isOsx
                    )}
                    .detail=${this.localize.term(
                      `formProviderExportTypes_${exportType.alias}Description`,
                      exportType.isOsx
                    )}
                    @selected=${this.#handleExportTypeSelection}
                  >
                    ${when(
                      exportType.icon,
                      () => html`<uui-icon name=${exportType.icon}></uui-icon>`
                    )}
                  </umb-ref-item>`
              )}
            </uui-ref-list>
          </div>
        </umb-property-layout>
      </uui-box>
      <div slot="actions">
        <uui-button
          label=${this.localize.term("general_close")}
          @click=${this._rejectModal}
        ></uui-button>
        <uui-button
          look="primary"
          color="positive"
          label=${this.localize.term("actions_export")}
          @click=${this.#export}
        ></uui-button>
      </div>
    </umb-body-layout>`;
  }
}

export default FormsExportEntriesModalElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsExportEntriesModalElement;
  }
}
