import type { UmbSorterConfig } from "@umbraco-cms/backoffice/sorter";

export class FormsSorterConfig {
  config: UmbSorterConfig<string>;

  constructor(identifier: string, itemSelector: string, containerSelector?: string) {
    this.config = {
      getUniqueOfElement: (element) => {
        return element.getAttribute("sort-unique");
      },
      getUniqueOfModel: (modelEntry) => {
        return modelEntry;
      },
      identifier,
      itemSelector,
      containerSelector,
    };
  }
}
