import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { UmbDetailRepositoryBase } from "@umbraco-cms/backoffice/repository";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import { FolderService } from "@umbraco-forms/generated";
import { FormsFormFolderServerDataSource } from "./form-folder-detail.server.data-source.js";
import { UmbFolderModel } from "@umbraco-cms/backoffice/tree";
import { FORMS_FORM_FOLDER_DETAIL_STORE_CONTEXT } from "./form-folder-detail.store.js";

export class FormsFormFolderDetailRepository extends UmbDetailRepositoryBase<
  UmbFolderModel,
  FormsFormFolderServerDataSource
> {

  constructor(host: UmbControllerHost) {
    super(host, FormsFormFolderServerDataSource, FORMS_FORM_FOLDER_DETAIL_STORE_CONTEXT);
  }

  async isEmpty(unique: string) {
		if (!unique) throw new Error('Unique is missing');
		return tryExecuteAndNotify(
			this._host,
			FolderService.getFolderByIdIsEmpty({
				id: unique,
			}),
		);
  }

  async moveFolder(unique: string, newParentId: string) {
    if (!unique) throw new Error("Unique is missing");

    const requestBody = {
      parentId: newParentId,
    };

    const { data, error } = await tryExecuteAndNotify(
      this._host,
      FolderService.putFolderByIdMove({
        id: unique,
        requestBody,
      })
    );

    if (error || !data) {
      return { error };
    }

    return { data };
  }
}
