import type {
  ManifestRepository,
  ManifestTreeStore,
} from "@umbraco-cms/backoffice/extension-registry";
import {
  FORMS_PREVALUESOURCE_ENTITY_TYPE,
  FORMS_PREVALUESOURCE_ROOT_ENTITY_TYPE,
} from "../entities.js";
import { FormsPrevalueSourceTreeRepository } from "./prevaluesources-tree.repository.js";
import { FormsPrevalueSourceTreeStore } from "./prevaluesources-tree.store.js";

import { manifests as menuManifests } from "./menu-item/manifests.js";
import { FormSecurityForUser } from "../../../generated/models.js";
import { FORMS_SECURITY_PERMISSION_CONDITION, FormsSecurityPermissionConditionConfig } from "../../security/conditions/security-permission-condition.config.js";
import { ManifestTree, ManifestTreeItem } from "@umbraco-cms/backoffice/tree";

export const FORMS_PREVALUESOURCE_TREE_REPOSITORY_ALIAS = "Forms.Repository.PrevalueSources.Tree";
export const FORMS_PREVALUESOURCE_TREE_STORE_ALIAS = "Forms.Store.PrevalueSources.Tree";
export const FORMS_PREVALUESOURCE_TREE_ALIAS = "Forms.Tree.PrevalueSources";

const treeRepository: ManifestRepository = {
  type: "repository",
  alias: FORMS_PREVALUESOURCE_TREE_REPOSITORY_ALIAS,
  name: "Prevalue Source Tree Repository",
  api: FormsPrevalueSourceTreeRepository,
};

const treeStore: ManifestTreeStore = {
  type: "treeStore",
  alias: FORMS_PREVALUESOURCE_TREE_STORE_ALIAS,
  name: "Prevalue Source Tree Store",
  api: FormsPrevalueSourceTreeStore,
};

const tree: ManifestTree = {
  type: "tree",
  kind: 'default',
  alias: FORMS_PREVALUESOURCE_TREE_ALIAS,
  name: "Prevalue Source Tree",
  meta: {
    repositoryAlias: FORMS_PREVALUESOURCE_TREE_REPOSITORY_ALIAS,
  },
  conditions: [
    {
      alias: FORMS_SECURITY_PERMISSION_CONDITION,
      match: (security: FormSecurityForUser) => security.userSecurity.managePreValueSources,
    } as FormsSecurityPermissionConditionConfig,
  ],
};

const treeItem: ManifestTreeItem = {
  type: "treeItem",
  kind: 'default',
  alias: "Forms.TreeItem.PrevalueSource",
  name: "Prevalue Source Tree Item",
  forEntityTypes: [FORMS_PREVALUESOURCE_ROOT_ENTITY_TYPE, FORMS_PREVALUESOURCE_ENTITY_TYPE],
};

export const manifests = [
  treeRepository,
  treeStore,
  tree,
  treeItem,
  ...menuManifests,
];
