import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import type { UmbTreeAncestorsOfRequestArgs, UmbTreeChildrenOfRequestArgs, UmbTreeRootItemsRequestArgs} from "@umbraco-cms/backoffice/tree";
import { UmbTreeServerDataSourceBase } from "@umbraco-cms/backoffice/tree";
import type { PrevalueSourceTreeItemResponseModel } from "@umbraco-forms/generated";
import { PrevalueSourceService } from "@umbraco-forms/generated";
import { FORMS_PREVALUESOURCE_ENTITY_TYPE, FORMS_PREVALUESOURCE_ROOT_ENTITY_TYPE } from "../entities.js";
import type { PrevalueSourceTreeItemModel } from "./types.js";

/**
 * A data source for the data sources tree that fetches data from the server
 * @export
 * @class FormsPrevalueSourceTreeServerDataSource
 */
export class FormsPrevalueSourceTreeServerDataSource extends UmbTreeServerDataSourceBase<
  PrevalueSourceTreeItemResponseModel,
  PrevalueSourceTreeItemModel
> {
  constructor(host: UmbControllerHost) {
    super(host, {
      getRootItems,
      getChildrenOf,
      getAncestorsOf,
      mapper,
    });
  }
}

// eslint-disable-next-line local-rules/no-direct-api-import
const getRootItems = (args: UmbTreeRootItemsRequestArgs) => PrevalueSourceService.getTreePrevalueSourceRoot();

const getChildrenOf = (args: UmbTreeChildrenOfRequestArgs) => {
	if (args.parent.unique === null) {
		return getRootItems(args);
	} else {
		throw new Error('Not supported for the data source tree');
	}
};

const getAncestorsOf = (args: UmbTreeAncestorsOfRequestArgs) => {
	throw new Error('Not supported for the data source tree');
};

const mapper = (item: PrevalueSourceTreeItemResponseModel): PrevalueSourceTreeItemModel => {
  return {
    unique: item.id,
		parent: {
			unique: null,
			entityType: FORMS_PREVALUESOURCE_ROOT_ENTITY_TYPE,
		},
    name: item.name,
    entityType: FORMS_PREVALUESOURCE_ENTITY_TYPE,
    isFolder: item.isFolder,
    hasChildren: item.hasChildren,
  };
};
