import { customElement, unsafeHTML } from "@umbraco-cms/backoffice/external/lit";
import { FormsFieldPreviewBaseElement } from './field-preview-base.element.js';

const elementName = "forms-field-preview-richtext"
@customElement(elementName)
export class FormsFieldPreviewRichtext extends FormsFieldPreviewBaseElement{
  render() {
    return unsafeHTML(this.getSettingValue("Html"));
  }
}

export default FormsFieldPreviewRichtext;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFieldPreviewRichtext;
  }
}
