import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import type { UmbCollectionDataSource } from "@umbraco-cms/backoffice/collection";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import type { RecordAuditEntry } from "@umbraco-forms/generated";
import { RecordService } from "@umbraco-forms/generated";
import type {
  FormEntryAuditCollectionFilterModel,
  FormEntryRecordAuditCollectionModel,
} from "../../types.js";

export class FormsFormEntryRecordAuditCollectionServerDataSource
  implements UmbCollectionDataSource<FormEntryRecordAuditCollectionModel>
{
  #host: UmbControllerHost;

  constructor(host: UmbControllerHost) {
    this.#host = host;
  }

  async getCollection(filter: FormEntryAuditCollectionFilterModel) {
    const { data, error } = await tryExecuteAndNotify(
      this.#host,
      RecordService.getFormByFormIdRecordByRecordIdAuditTrail(
        filter
      )
    );

    if (error) {
      return { error };
    }

    if (!data) {
      return { data: { items: [], total: 0 } };
    }

    const mappedItems: Array<FormEntryRecordAuditCollectionModel> = data.map(
      (item: RecordAuditEntry) => {
        const record: FormEntryRecordAuditCollectionModel = {
          entityType: "forms-record-audit-entry",
          unique: item.id.toString(),
          updatedBy: item.updatedBy,
          updatedOn: new Date(item.updatedOn),
        };

        return record;
      }
    );

    return { data: { items: mappedItems, total: mappedItems.length } };
  }
}
