import type { UmbCollectionRepository } from '@umbraco-cms/backoffice/collection';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import { FormsWorkflowTypeCollectionServerDataSource } from './workflow-type-collection.server.data-source.js';

export class FormsWorkflowTypeCollectionRepository implements UmbCollectionRepository {
	#collectionSource: FormsWorkflowTypeCollectionServerDataSource;

	constructor(host: UmbControllerHost) {
		this.#collectionSource = new FormsWorkflowTypeCollectionServerDataSource(host);
	}

	async requestCollection() {
		return this.#collectionSource.getCollection();
	}

	destroy(): void {}
}

export default FormsWorkflowTypeCollectionRepository;
