import type { UmbCollectionRepository } from '@umbraco-cms/backoffice/collection';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import type { FormEntryAuditCollectionFilterModel } from '../../types.js';
import { FormsFormEntryWorkflowAuditCollectionServerDataSource } from './entry-workflow-audit-collection.server.data-source.js';

export class FormsFormEntryWorkflowAuditCollectionRepository implements UmbCollectionRepository {
	#collectionSource: FormsFormEntryWorkflowAuditCollectionServerDataSource;

	constructor(host: UmbControllerHost) {
		this.#collectionSource = new FormsFormEntryWorkflowAuditCollectionServerDataSource(host);
	}

	async requestCollection(filter: FormEntryAuditCollectionFilterModel = {
		formId: '',
		recordId: ''
	}) {
		return this.#collectionSource.getCollection(filter);
	}

	async executeWorkflow(formId: string, recordId: string, workflowId: string) {
		await this.#collectionSource.executeWorkflow(formId, recordId, workflowId);
	}

	destroy(): void {}
}

export default FormsFormEntryWorkflowAuditCollectionRepository;
