import { UmbModalToken } from "@umbraco-cms/backoffice/modal";
import { AllowedUploadType, FieldTypeWithSettings, Field, FieldCondition, FieldPreValueSource, FieldPrevalue, ValidationPattern, Page } from "@umbraco-forms/generated";

export const FORMS_EDIT_FIELD_MODAL_ALIAS = "Umb.Modal.Forms.EditField";

export interface FormsEditFieldModalData {
  fields: Array<Field>,
  pages: Array<Page>,
  validationPatterns: Array<ValidationPattern>,
  prevalueSources: Array<FieldPreValueSource>,
  isNew: boolean
}

export interface FormsEditFieldModalValue {
  caption: string,
  alias: string,
  tooltip?: string | null,
  fieldType: FieldTypeWithSettings,
  containsSensitiveData: boolean,
  allowMultipleFileUploads: boolean,
  allowedUploadTypes: Array<AllowedUploadType> | null | undefined,
  prevalues: Array<FieldPrevalue>,
  prevalueSourceId?: string | null,
  condition: FieldCondition;
  mandatory: boolean,
  requiredErrorMessage?: string | null,
  regex?: string | null,
  invalidErrorMessage?: string | null,
  settings: Record<string, string>,
  containerIndexPath: string
}

export const FORMS_EDIT_FIELD_MODAL = new UmbModalToken<
  FormsEditFieldModalData,
  FormsEditFieldModalValue
>(FORMS_EDIT_FIELD_MODAL_ALIAS, {
  modal: {
    type: "sidebar",
    size: "medium",
  },
});
