import { customElement, html } from "@umbraco-cms/backoffice/external/lit";
import { FormsFieldPreviewBaseElement } from './field-preview-base.element.js';

const elementName = "forms-field-preview-checkbox"
@customElement(elementName)
export class FormsFieldPreviewCheckbox extends FormsFieldPreviewBaseElement{
  render() {
    return html`<input type="checkbox" disabled tabindex="-1"/>`;
  }
}

export default FormsFieldPreviewCheckbox;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFieldPreviewCheckbox;
  }
}
