import { UmbId } from "@umbraco-cms/backoffice/id";
import type { UmbDetailDataSource } from "@umbraco-cms/backoffice/repository";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import type { FormSecurityForUser } from "@umbraco-forms/generated";
import { SecurityService } from "@umbraco-forms/generated";
import { FORMS_SECURITY_USER_ENTITY_TYPE } from "../../../entities.js";

export class FormsSecurityUserDetailServerDataSource
  implements UmbDetailDataSource<FormSecurityForUser>
{
  #host: UmbControllerHost;

  constructor(host: UmbControllerHost) {
    this.#host = host;
  }

  async createScaffold(preset: Partial<FormSecurityForUser> = {}) {
    const unique = preset.unique ? preset.unique : UmbId.new();
    const data: FormSecurityForUser = {
      entityType: FORMS_SECURITY_USER_ENTITY_TYPE,
      unique: unique,
      name: "",
      key: unique,
      userSecurity: {
        manageDataSources: false,
        managePreValueSources: false,
        manageWorkflows: false,
        manageForms: false,
        viewEntries: false,
        editEntries: false,
        deleteEntries: false,
        user: "",
      },
      startFolderIds: [],
      formsSecurity: [],
    };

    return { data };
  }

  async read(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    const { data, error } = await tryExecuteAndNotify(
      this.#host,
      SecurityService.getSecurityUserByIdFormSecurity(
        { id: unique }
      )
    );

    if (error || !data) {
      return { error };
    }

    // TODO => this should be mapped, not cast
    return { data: data as FormSecurityForUser };
  }

  async create(security: FormSecurityForUser) {
    if (!security) throw new Error("Security item is missing");
    if (!security.unique) throw new Error("Security item unique is missing");

    const { error: createError } = await tryExecuteAndNotify(
      this.#host,
      SecurityService.postSecurityUserByIdFormSecurity(
        {
          id: security.unique,
          requestBody: security,
        }
      )
    );

    if (createError) {
      return { error: createError };
    }

    return this.read(security.unique);
  }

  async update(security: FormSecurityForUser) {
    if (!security.unique) throw new Error("Unique is missing");

    const { error } = await tryExecuteAndNotify(
      this.#host,
      SecurityService.putSecurityUserByIdFormSecurity(
        {
          id: security.unique,
          requestBody: security,
        }
      )
    );

    if (error) {
      return { error };
    }

    return this.read(security.unique);
  }

  async delete(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    return tryExecuteAndNotify(
      this.#host,
      SecurityService.deleteSecurityUserByIdFormSecurity(
        {
          id: unique,
        }
      )
    );
  }
}
