import type { UmbEntryPointOnInit } from "@umbraco-cms/backoffice/extension-api";
import { UMB_AUTH_CONTEXT } from "@umbraco-cms/backoffice/auth";
import { OpenAPI } from "@umbraco-forms/generated";

import { manifests as localizationManifests } from "./lang/manifests.js";
import { manifests as sectionManifests } from "./section/manifests.js";
import { manifests as modalManifests } from "./modal/manifests.js";
import { manifests as propertyEditorManifests } from "./property-editor/manifests.js";
import { manifests as contextManifests } from "./context/manifests.js";
import { manifests as FormBuildermManifests } from "./ufm/manifests.js";

export * from "./section/index.js";
export * from "./components/index.js";
export * from "./modal/index.js";
export * from "./context/index.js";

const manifests: Array<UmbExtensionManifest> = [
  ...contextManifests,
  ...sectionManifests,
  ...localizationManifests,
  ...modalManifests,
  ...propertyEditorManifests,
  ...ufmManifests,
];

export const onInit: UmbEntryPointOnInit = (host, extensionRegistry) => {
  extensionRegistry.registerMany(manifests);

  host.consumeContext(UMB_AUTH_CONTEXT, async (instance) => {
    if (!instance) return;

    OpenAPI.TOKEN = () => instance.getLatestToken();
    OpenAPI.WITH_CREDENTIALS = true;
  });
};
