import type {
  UmbDataSourceResponse,
  UmbDetailDataSource,
} from "@umbraco-cms/backoffice/repository";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import type { FieldTypeWithSettings } from "@umbraco-forms/generated";
import { FieldTypeService } from "@umbraco-forms/generated";

export class FormsFieldTypeDetailServerDataSource
  implements UmbDetailDataSource<FieldTypeWithSettings>
{
  #host: UmbControllerHost;

  constructor(host: UmbControllerHost) {
    this.#host = host;
  }

  async read(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    const { data, error } = await tryExecuteAndNotify(
      this.#host,
      FieldTypeService.getFieldTypeById({
        id: unique,
      })
    );

    if (error || !data) {
      return { error };
    }

    return { data: data as FieldTypeWithSettings };
  }

  createScaffold(
    preset?: Partial<FieldTypeWithSettings> | undefined
  ): Promise<UmbDataSourceResponse<FieldTypeWithSettings>> {
    throw new Error("Method not implemented.");
  }

  create(
    data: FieldTypeWithSettings,
    parentUnique: string | null
  ): Promise<UmbDataSourceResponse<FieldTypeWithSettings>> {
    throw new Error("Method not implemented.");
  }

  update(
    data: FieldTypeWithSettings
  ): Promise<UmbDataSourceResponse<FieldTypeWithSettings>> {
    throw new Error("Method not implemented.");
  }

  delete(unique: string): Promise<UmbDataSourceResponse<unknown>> {
    throw new Error("Method not implemented.");
  }
}
