import { customElement, html } from "@umbraco-cms/backoffice/external/lit";
import { FormsFieldPreviewBaseElement } from './field-preview-base.element.js';

const elementName = "forms-field-preview-recaptchav2"
@customElement(elementName)
export class FormsFieldPreviewRecaptchaV2 extends FormsFieldPreviewBaseElement{
  render() {
    return html`<script src="https://www.google.com/recaptcha/api.js" async defer type="application/javascript"></script>`;
  }
}

export default FormsFieldPreviewRecaptchaV2;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFieldPreviewRecaptchaV2;
  }
}
