import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { UmbDetailRepositoryBase } from "@umbraco-cms/backoffice/repository";
import {
  RecordService,
  type FormDesign,
  FormService,
  FormTemplateService,
} from "@umbraco-forms/generated";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import { FORMS_FORM_DETAIL_STORE_CONTEXT } from "./form-detail.store.js";
import { FormsFormDetailServerDataSource } from "./form-detail.server.data-source.js";

export class FormsFormDetailRepository extends UmbDetailRepositoryBase<FormDesign> {
  constructor(host: UmbControllerHost) {
    super(
      host,
      FormsFormDetailServerDataSource,
      FORMS_FORM_DETAIL_STORE_CONTEXT
    );
  }

  async requestRecordsMetaData(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    const { data, error } = await tryExecuteAndNotify(
      this._host,
      RecordService.getFormByFormIdRecordMetadata({
        formId: unique,
      })
    );

    if (error || !data) {
      return { error };
    }

    return { data };
  }

  async requestHasRelations(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    const { data, error } = await tryExecuteAndNotify(
      this._host,
      FormService.getFormByIdHasRelations({
        id: unique,
      })
    );

    if (error || !data) {
      return { error };
    }

    return { data };
  }

  async requestTemplates() {
    const { data, error } = await tryExecuteAndNotify(
      this._host,
      FormTemplateService.getFormTemplate()
    );

    if (error || !data) {
      return { error };
    }

    return { data };
  }

  async requestFormScaffold(template: string) {
    const method =
      template.length === 0
        ? tryExecuteAndNotify(
            this,
            FormService.getFormScaffold()
          )
        : tryExecuteAndNotify(
            this,
            FormService.getFormScaffoldByTemplate({
              template: template,
            })
          );
    const { data, error } = await tryExecuteAndNotify(this._host, method);

    if (error || !data) {
      return { error };
    }

    return { data };
  }

  async copyForm(
    unique: string,
    copyWorkflows: boolean,
    newName?: string,
    copyToFolderId?: string
  ) {
    if (!unique) throw new Error("Unique is missing");

    const requestBody = {
      newName,
      copyWorkflows,
      copyToFolderId,
    };
    const { data, error } = await tryExecuteAndNotify(
      this._host,
      FormService.postFormByIdCopy({
        id: unique,
        requestBody,
      })
    );

    if (error) {
      return { error };
    }

    return { data };
  }

  async copyFormWorkflows(
    sourceId: string,
    destinationId: string,
    workflowIds: Array<string>
  ) {
    if (!sourceId) throw new Error("sourceId is missing");
    if (!destinationId) throw new Error("destinationId is missing");

    const requestBody = {
      sourceId,
      destinationId,
      workflowIds,
    };
    const { data, error } = await tryExecuteAndNotify(
      this._host,
      FormService.postFormByIdCopyWorkflows({
        id: sourceId,
        requestBody,
      })
    );

    if (error) {
      return { error };
    }

    return { data };
  }

  async moveForm(unique: string, newParentId: string) {
    if (!unique) throw new Error("Unique is missing");

    const requestBody = {
      parentId: newParentId,
    };
    const { data, error } = await tryExecuteAndNotify(
      this._host,
      FormService.putFormByIdMove({
        id: unique,
        requestBody,
      })
    );

    if (error) {
      return { error };
    }

    return { data };
  }
}
