import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import type { UmbApi } from '@umbraco-cms/backoffice/extension-api';
import { UmbTreeRepositoryBase } from '@umbraco-cms/backoffice/tree';
import { FORMS_PREVALUESOURCE_ROOT_ENTITY_TYPE } from '../entities.js';
import { FormsPrevalueSourceTreeServerDataSource } from './prevaluesources-tree.server.data-source.js';
import type { PrevalueSourceTreeItemModel, PrevalueSourceTreeRootModel } from './types.js';
import { FORMS_PREVALUESOURCE_TREE_STORE_CONTEXT } from './prevaluesources-tree.store.js';

export class FormsPrevalueSourceTreeRepository
	extends UmbTreeRepositoryBase<PrevalueSourceTreeItemModel, PrevalueSourceTreeRootModel>
	implements UmbApi
{
	constructor(host: UmbControllerHost) {
		super(host, FormsPrevalueSourceTreeServerDataSource, FORMS_PREVALUESOURCE_TREE_STORE_CONTEXT);
	}

	async requestTreeRoot() {
		const data: PrevalueSourceTreeRootModel = {
			unique: null,
			entityType: FORMS_PREVALUESOURCE_ROOT_ENTITY_TYPE,
			name: 'Prevalue Sources',
			hasChildren: true,
			isFolder: true,
		};

		return { data };
	}
}
