import {
  customElement,
  html,
  property,
  state,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import type { UUIInputEvent } from "@umbraco-cms/backoffice/external/uui";
import { FormsSettingsElementBaseElement } from "./forms-settings-element-base.element.js";

const elementName = "forms-settings-data-retention-stage";

@customElement(elementName)
export class FormsSettingsDataRetentionStageElement extends FormsSettingsElementBaseElement {
  #previousValue = 365;

  @state()
  _showDaysToRetain = false;

  @property()
  stage = "";

  connectedCallback(): void {
    super.connectedCallback();
    this._showDaysToRetain = this.form[this.#getPropertyKey()] > 0;
  }

  #getValue() {
    return this.form[this.#getPropertyKey()];
  }

  #setValue(value: number) {
    return this.setPropertyValue(this.#getPropertyKey(), value);
  }

  #getPropertyKey() {
    return `daysToRetain${this.stage}RecordsFor`;
  }

  #onToggleChange() {
    this._showDaysToRetain = !this._showDaysToRetain;

    // If retaining state forever, reset model value to 0 and save previous value.
    if (!this._showDaysToRetain) {
      this.#previousValue = this.#getValue();
      this.#setValue(0);
    } else {
      // If switching to delete after X days, set a sensible default (either the previous entered value, or for one year).
      this.#setValue(this.#previousValue);
    }
  }

  render() {
    return html` <div>
      <uui-toggle
        ?checked=${this._showDaysToRetain}
        .label=${this.localize.term(
          `formSettings_dataRetention${this._showDaysToRetain ? "Remove" : "Retain"}${this.stage}Records`
        )}
        @change=${this.#onToggleChange}
      ></uui-toggle>
      ${when(
        this._showDaysToRetain,
        () => html`<div>
          <uui-label>
            ${this.localize.term(
              `formSettings_dataRetentionFor${this.stage}Records`
            )}
          </uui-label>
          <uui-input
            type="number"
            name="numberOfDays"
            .value=${this.#getValue()}
            @change=${(e: UUIInputEvent) =>
              this.onInputChange(e, this.#getPropertyKey())}
            label="numberOfDays"
          ></uui-input>
        </div>`
      )}
    </div>`;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsSettingsDataRetentionStageElement;
  }
}
