import { UmbId } from "@umbraco-cms/backoffice/id";
import type { UmbDetailDataSource } from "@umbraco-cms/backoffice/repository";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import type { FormSecurityForGroup } from "@umbraco-forms/generated";
import { SecurityService } from "@umbraco-forms/generated";
import { FORMS_SECURITY_USER_GROUP_ENTITY_TYPE } from "../../../entities.js";

export class FormsSecurityUserGroupDetailServerDataSource
  implements UmbDetailDataSource<FormSecurityForGroup>
{
  #host: UmbControllerHost;

  constructor(host: UmbControllerHost) {
    this.#host = host;
  }

  async createScaffold(preset: Partial<FormSecurityForGroup> = {}) {
    const data: FormSecurityForGroup = {
      entityType: FORMS_SECURITY_USER_GROUP_ENTITY_TYPE,
      unique: UmbId.new(),
      name: "",
      key: "",
      userGroupSecurity: {
        manageDataSources: false,
        managePreValueSources: false,
        manageWorkflows: false,
        manageForms: false,
        viewEntries: false,
        editEntries: false,
        deleteEntries: false,
        userGroupId: 0,
      },
      startFolderIds: [],
      formsSecurity: [],
    };

    return { data };
  }

  async read(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    const { data, error } = await tryExecuteAndNotify(
      this.#host,
      SecurityService.getSecurityUserGroupByIdFormSecurity(
        { id: unique }
      )
    );

    if (error || !data) {
      return { error };
    }

    // TODO => this should be mapped, not cast
    return { data: data as FormSecurityForGroup };
  }

  async create(security: FormSecurityForGroup) {
    if (!security) throw new Error("Security item is missing");
    if (!security.unique) throw new Error("Security item unique is missing");

    const { error: createError } = await tryExecuteAndNotify(
      this.#host,
      SecurityService.postSecurityUserGroupByIdFormSecurity(
        {
          id: security.unique,
          requestBody: security,
        }
      )
    );

    if (createError) {
      return { error: createError };
    }

    return this.read(security.unique);
  }

  async update(security: FormSecurityForGroup) {
    if (!security.unique) throw new Error("Unique is missing");

    const { error } = await tryExecuteAndNotify(
      this.#host,
      SecurityService.putSecurityUserGroupByIdFormSecurity(
        {
          id: security.unique,
          requestBody: security,
        }
      )
    );

    if (error) {
      return { error };
    }

    return this.read(security.unique);
  }

  async delete(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    return tryExecuteAndNotify(
      this.#host,
      SecurityService.deleteSecurityUserGroupByIdFormSecurity(
        {
          id: unique,
        }
      )
    );
  }
}
