import { css, html, customElement, property, state, repeat } from '@umbraco-cms/backoffice/external/lit';
import { UmbLitElement } from '@umbraco-cms/backoffice/lit-element';
import { splitStringToArray } from '@umbraco-cms/backoffice/utils';
import { UUIFormControlMixin } from '@umbraco-cms/backoffice/external/uui';
import type { FormItemModel } from '../../section/forms/repository/index.js';
import type { FormTreeItemModel } from '../../section/forms/tree/index.js';
import { FormsFolderPickerContext } from './input-form-folder.context.js';

const elementName = "forms-input-folder";

@customElement(elementName)
export class FormsInputFolderElement extends UUIFormControlMixin(UmbLitElement, '') {

	public get selection(): Array<string> {
		return this.#pickerContext.getSelection();
	}
	public set selection(ids: Array<string>) {
		this.#pickerContext.setSelection(ids ?? []);
	}

	@property()
	public set value(idsString: string) {
		this.selection = splitStringToArray(idsString);
	}
	public get value() {
		return this.selection.join(',');
	}

	@state()
	private _items?: Array<FormItemModel>;

	#pickerContext = new FormsFolderPickerContext(this);

	constructor() {
		super();

		this.observe(this.#pickerContext.selection, (selection) => (this.value = selection.join(',')));
		this.observe(this.#pickerContext.selectedItems, (selectedItems) => (this._items = selectedItems));
	}

	connectedCallback(): void {
		super.connectedCallback();
	}

	protected getFormElement() {
		return undefined;
	}

	#pickableFilter: (item: FormTreeItemModel) => boolean = (item) => {
		return item.isFolder;
	};

	#openPicker() {
		this.#pickerContext.openPicker({
			pickableFilter: this.#pickableFilter,
		});
	}

	render() {
		return html`${this.#renderItems()} ${this.#renderAddButton()}`;
	}

	#renderItems() {
		if (!this._items?.length) return;
		return html`<uui-ref-list>
			${repeat(
			this._items,
			(item) => item.unique,
			(item) => this.#renderItem(item),
		)}
		</uui-ref-list>`;
	}

	#renderAddButton() {
		return html`<uui-button
			id="add-button"
			look="placeholder"
			@click=${this.#openPicker}
			label=${this.localize.term('general_choose')}></uui-button>`;
	}

	#renderItem(item: FormItemModel) {
		if (!item.unique) return;

		return html`
			<uui-ref-node name=${item.name}>
				<umb-icon slot="icon" name="icon-folder"></umb-icon>
				<uui-action-bar slot="actions">
					<uui-button
						@click=${() => this.#pickerContext.requestRemoveItem(item.unique)}
						label=${this.localize.term('formPicker_removeItemButtonLabel', item.name)}>
						${this.localize.term('general_remove')}
					</uui-button>
				</uui-action-bar>
			</uui-ref-node>
		`;
	}

	static styles = [
		css`
			#add-button {
				width: 100%;
			}

			uui-ref-node[drag-placeholder] {
				opacity: 0.2;
			}
		`,
	];
}

export default FormsInputFolderElement;

declare global {
	interface HTMLElementTagNameMap {
		[elementName]: FormsInputFolderElement;
	}
}
