import { UmbItemServerDataSourceBase } from '@umbraco-cms/backoffice/repository';
import { FolderService, type FolderItemResponseModel } from "@umbraco-forms/generated";
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import type { FolderItemModel } from './types.js';

export class FormsFolderItemServerDataSource extends UmbItemServerDataSourceBase<
	FolderItemResponseModel,
	FolderItemModel
> {
	constructor(host: UmbControllerHost) {
		super(host, {
			getItems,
			mapper,
		});
	}
}

/* eslint-disable local-rules/no-direct-api-import */
const getItems = (uniques: Array<string>) => FolderService.getItemFolder({ id: uniques });

const mapper = (item: FolderItemResponseModel): FolderItemModel => {
	return {
		unique: item.id,
		name: item.name
	};
};
