import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import {
  LitElement,
  css,
  customElement,
  html,
  property,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import { UMB_MODAL_MANAGER_CONTEXT } from "@umbraco-cms/backoffice/modal";
import type { FormsLicenseModel } from "@umbraco-forms/generated";
import {
  FORMS_BUY_LICENSE_MODAL,
  FORMS_CONFIGURE_LICENSE_MODAL,
} from "../modal/index.js";

const elementName = "forms-licensing";

@customElement(elementName)
export class FormsDashboardLicensingElement extends UmbElementMixin(
  LitElement
) {
  @property({ type: Object })
  status?: FormsLicenseModel;

  async #buyLicense() {
    const modalContext = await this.getContext(UMB_MODAL_MANAGER_CONTEXT);
    const modalHandler = modalContext.open(this, FORMS_BUY_LICENSE_MODAL);
    await modalHandler.onSubmit().catch(() => undefined);
  }

  async #configureLicense() {
    const modalContext = await this.getContext(UMB_MODAL_MANAGER_CONTEXT);
    const modalHandler = modalContext.open(this, FORMS_CONFIGURE_LICENSE_MODAL);
    await modalHandler.onSubmit().catch(() => undefined);
  }

  #renderInvalid() {
    return html`<div class="alert alert-error">
      <h4>${this.localize.term("formsDashboard_invalidLicense")}</h4>
      ${this.localize.term("formsDashboard_invalidLicenseValidFor")}
      <pre>${this.status?.licenseLimitations}</pre>
      ${this.localize.term("formsDashboard_reconfigure")}
    </div>`;
  }

  #renderNoState() {
    return html` <div id="noState">
      <div id="noStateHeader">
        <h3>${this.localize.term("formsDashboard_trialTitle")}</h3>
        <p>${this.localize.term("formsDashboard_trialDescription")}</p>
      </div>

      <div id="noStateOptions">
        <uui-button
          look="primary"
          color="positive"
          @click=${this.#buyLicense}
          .label=${this.localize.term("formsDashboard_buyLicense")}
        ></uui-button>
        <uui-button
          look="primary"
          color="default"
          @click=${this.#configureLicense}
          .label=${this.localize.term("formsDashboard_configureLicense")}
        ></uui-button>
      </div>
    </div>`;
  }

  render() {
    return when(
      this.status?.isInvalid || this.status?.isTrial,
      () => html`<uui-box>
        ${when(this.status?.isInvalid, () => this.#renderInvalid())}
        ${this.#renderNoState()}
      </uui-box> `
    );
  }

  // TODO => standardise alert styling between DXP products (maybe CMS?)
  static styles = [
    css`
      .alert {
        border-left: 4px solid;
        border-radius: var(--uui-border-radius);
        padding: var(--uui-size-3);
      }

      .alert-error {
        border-left-color: var(--uui-color-danger);
      }
    `,
  ];
}

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsDashboardLicensingElement;
  }
}
