import type { UmbCollectionDataSource } from "@umbraco-cms/backoffice/collection";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import type { Theme } from "@umbraco-forms/generated";
import { ThemeService } from "@umbraco-forms/generated";
import type { ThemeCollectionModel } from "./types.js";

export class ThemeCollectionServerDataSource
  implements UmbCollectionDataSource<ThemeCollectionModel>
{
  #host: UmbControllerHost;

  constructor(host: UmbControllerHost) {
    this.#host = host;
  }

  async getCollection() {
    const { data, error } = await tryExecuteAndNotify(
      this.#host,
      ThemeService.getTheme()
    );

    if (error) {
      return { error };
    }

    if (!data) {
      return { data: { items: [], total: 0 } };
    }

    const mappedItems: Array<ThemeCollectionModel> = data.map((item: Theme) => {
      const record: ThemeCollectionModel = {
        name: item.name,
        entityType: "forms-theme",
        unique: item.name
      };

      return record;
    });

    return { data: { items: mappedItems, total: mappedItems.length } };
  }
}
