import type { ManifestRepository, ManifestItemStore } from '@umbraco-cms/backoffice/extension-registry';
import { FormsFormItemStore } from './form-item.store.js';
import { FormsFormItemRepository } from './form-item.repository.js';
import { FormsFolderItemStore } from './folder-item.store.js';
import { FormsFolderItemRepository } from './folder-item.repository.js';

export const FORMS_FORM_ITEM_REPOSITORY_ALIAS = 'Forms.Repository.Form.Item';
export const FORMS_FOLDER_ITEM_REPOSITORY_ALIAS = 'Forms.Repository.Folder.Item';

export const FORMS_FORM_STORE_ALIAS = 'Forms.Store.Form.Item';
export const FORMS_FOLDER_STORE_ALIAS = 'Forms.Store.Folder.Item';


const repositories: Array<ManifestRepository> = [
	{
		type: 'repository',
		alias: FORMS_FORM_ITEM_REPOSITORY_ALIAS,
		name: 'Forms Form Item Repository',
		api: FormsFormItemRepository,
	},
	{
		type: 'repository',
		alias: FORMS_FOLDER_ITEM_REPOSITORY_ALIAS,
		name: 'Forms Folder Item Repository',
		api: FormsFolderItemRepository,
	}
];

const stores: Array<ManifestItemStore> = [
	{
		type: 'itemStore',
		alias: FORMS_FORM_STORE_ALIAS,
		name: 'Forms Form Item Store',
		api: FormsFormItemStore,
	},
	{
		type: 'itemStore',
		alias: FORMS_FOLDER_STORE_ALIAS,
		name: 'Forms Folder Item Store',
		api: FormsFolderItemStore,
	}
];

export const manifests = [...repositories, ...stores];
