import { UmbId } from "@umbraco-cms/backoffice/id";
import type { UmbDetailDataSource } from "@umbraco-cms/backoffice/repository";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import type { FieldPreValueSource } from "@umbraco-forms/generated";
import { PrevalueSourceService } from "@umbraco-forms/generated";
import { FORMS_PREVALUESOURCE_ENTITY_TYPE } from "../../entities.js";

/**
 * A data source for the Form that fetches data from the server
 * @export
 * @class FormsPrevalueSourceDetailServerDataSource
 * @implements {RepositoryDetailDataSource}
 */
export class FormsPrevalueSourceDetailServerDataSource
  implements UmbDetailDataSource<FieldPreValueSource>
{
  #host: UmbControllerHost;

  constructor(host: UmbControllerHost) {
    this.#host = host;
  }

  /**
   * Creates a new prevalue source scaffold
   * @param {(string | null)} parentUnique
   * @return { FieldPreValueSource }
   * @memberof FormsPrevalueSourceDetailServerDataSource
   */
  async createScaffold(preset: Partial<FieldPreValueSource> = {}) {
    const data: FieldPreValueSource = {
      entityType: FORMS_PREVALUESOURCE_ENTITY_TYPE,
      unique: UmbId.new(),
      id: UmbId.new(),
      created: "",
      name: "",
      settings: {},
      fieldPreValueSourceTypeId: "",
      cachePrevaluesFor: "",
      updated: ""
    };

    return { data };
  }

  /**
   * Fetches a prevalue source with the given id from the server
   * @param {string} unique
   * @return {FieldPreValueSource}
   * @memberof FormsPrevalueSourceDetailServerDataSource
   */
  async read(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    const { data, error } = await tryExecuteAndNotify(
      this.#host,
      PrevalueSourceService.getPrevalueSourceById({
        id: unique,
      })
    );

    if (error || !data) {
      return { error };
    }

    return { data };
  }

  /**
   * Inserts a new prevalue source on the server
   * @param {FormDetailModel} form
   * @return {*}
   * @memberof FormsPrevalueSourceDetailServerDataSource
   */
  async create(prevalueSource: FieldPreValueSource) {
    if (!prevalueSource) throw new Error("Prevalue source is missing");
    if (!prevalueSource.unique)
      throw new Error("Prevalue source unique is missing");

    const { error: createError } = await tryExecuteAndNotify(
      this.#host,
      PrevalueSourceService.postPrevalueSource({
        requestBody: prevalueSource,
      })
    );

    if (createError) {
      return { error: createError };
    }

    // We have to fetch the data type again. The server can have modified the data after creation
    return this.read(prevalueSource.unique);
  }

  /**
   * Updates a prevalue source on the server
   * @param {FormDetailModel} Form
   * @return {*}
   * @memberof FormsPrevalueSourceDetailServerDataSource
   */
  async update(prevalueSource: FieldPreValueSource) {
    if (!prevalueSource.unique) throw new Error("Unique is missing");

    const { error } = await tryExecuteAndNotify(
      this.#host,
      PrevalueSourceService.putPrevalueSourceById({
        id: prevalueSource.id,
        requestBody: prevalueSource,
      })
    );

    if (error) {
      return { error };
    }

    // We have to fetch the form again. The server can have modified the data after update
    return this.read(prevalueSource.unique);
  }

  /**
   * Deletes a prevalue source on the server
   * @param {string} unique
   * @return {*}
   * @memberof FormsPrevalueSourceDetailServerDataSource
   */
  async delete(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    return tryExecuteAndNotify(
      this.#host,
      PrevalueSourceService.deletePrevalueSourceById({
        id: unique,
      })
    );
  }
}
