import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import type { UmbCollectionDataSource } from "@umbraco-cms/backoffice/collection";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import type { EntrySearchResult } from "@umbraco-forms/generated";
import { RecordService, RecordSorting } from "@umbraco-forms/generated";
import { UmbControllerBase } from "@umbraco-cms/backoffice/class-api";
import { encodeFolderName } from "@umbraco-cms/backoffice/router";
import { FORMS_ENTRY_DETAILS_MODAL } from "@umbraco-forms/modals";
import { first, firstValueFrom } from "@umbraco-cms/backoffice/external/rxjs";
import { FORMS_FORM_ENTRY_ENTITY_TYPE } from "../../../entities.js";
import type {
  FormEntryCollectionFilterModel,
  FormEntryCollectionModel,
} from "../../types.js";
import { FORMS_FORM_WORKSPACE_CONTEXT } from "../../../workspace/form-workspace.context-token.js";
import { FORMS_FORM_ENTRY_COLLECTION_CONTEXT } from "../form-entry-collection.context-token.js";

export class FormsFormEntryCollectionServerDataSource
  extends UmbControllerBase
  implements UmbCollectionDataSource<FormEntryCollectionModel>
{
  #host: UmbControllerHost;
  #formId?: string;

  constructor(host: UmbControllerHost) {
    super(host);
    this.#host = host;
  }

  async getCollection(filter: FormEntryCollectionFilterModel) {
    const context = await this.getContext(FORMS_FORM_WORKSPACE_CONTEXT);
    this.#formId = await firstValueFrom(context.unique.pipe(first(value => Boolean(value))));

    if (!this.#formId) return { data: { total: 0, items: [] } };

    if (
      location.href.includes(
        `modal/${encodeFolderName(FORMS_ENTRY_DETAILS_MODAL.toString())}`
      )
    ) {
      const recordId = location.href.split("/").pop();

      // don't update filterModel, reuse the values
      const currentPage =
        (await RecordService.getFormByFormIdRecordPageNumber({
          recordId,
          skip: 0,
          take: filter.take,
          formId: this.#formId,
          sortBy: "created",
          sortOrder: RecordSorting.DESCENDING,
        })) ?? 1;

      filter = {
        ...filter,
        ...{ skip: (currentPage - 1) * filter.take },
      };

      const collectionContext = await this.getContext(FORMS_FORM_ENTRY_COLLECTION_CONTEXT);
      collectionContext.pagination.setCurrentPageNumber(currentPage);
    }

    filter = { ...filter, ...{ formId: this.#formId } };

    const { data, error } = await tryExecuteAndNotify(
      this.#host,
      RecordService.getFormByFormIdRecord(filter)
    );

    if (error) {
      return { error };
    }

    if (!data) {
      return { data: { items: [], total: 0 } };
    }

    const { schema, results, totalNumberOfResults } = data;

    const mappedItems: Array<FormEntryCollectionModel> = results.map(
      (item: EntrySearchResult) => {
        const entryDetail: FormEntryCollectionModel = {
          unique: item.uniqueId,
          entityType: FORMS_FORM_ENTRY_ENTITY_TYPE,
          id: item.id,
          created: new Date(item.created),
          updated: new Date(item.updated),
          state: item.state,
          pageName: item.umbracoPage?.name,
          documentUnique: item.umbracoPage?.unique,
          fields: item.fields,
          member: item.member,
        };

        return entryDetail;
      }
    );

    // Rather a hack, but as we have an endpoint that returns schema (column) information, and we need to pass information to
    // the rendering via FormEntryCollectionModel, we'll populate the top record with the schema details.
    mappedItems.unshift({
      entityType: FORMS_FORM_ENTRY_ENTITY_TYPE,
      schema,
      unique: "",
      fields: [],
      id: 0,
      created: new Date(),
      updated: new Date(),
      state: "",
      pageName: "",
      documentUnique: "",
    });

    return { data: { items: mappedItems, total: totalNumberOfResults } };
  }

  async execute(formId: string, recordIds: Array<string>, actionId: string) {
    const requestBody = { recordKeys: recordIds };
    return tryExecuteAndNotify(
      this.#host,
      RecordService.postFormByFormIdRecordActionsByActionIdExecute({
        formId,
        actionId,
        requestBody,
      })
    );
  }
}
