import type { UmbEntityBulkActionArgs} from '@umbraco-cms/backoffice/entity-bulk-action';
import { UmbEntityBulkActionBase } from '@umbraco-cms/backoffice/entity-bulk-action';
import type { UmbControllerHostElement } from '@umbraco-cms/backoffice/controller-api';
import type { UmbDefaultCollectionContext } from '@umbraco-cms/backoffice/collection';
import { UMB_COLLECTION_CONTEXT } from '@umbraco-cms/backoffice/collection';
import { FORMS_FORM_WORKSPACE_CONTEXT } from '../../../form-workspace.context-token.js';
import type { FormsFormWorkspaceContext } from '../../../form-workspace.context.js';
import { FormsFormEntryCollectionRepository } from '../../../../entries/collection/repository/index.js';

export class EntryBulkActionBase extends UmbEntityBulkActionBase<object> {

	#workspaceContext?: FormsFormWorkspaceContext;
	#collectionContext?: UmbDefaultCollectionContext;

	#action: string = "";

	constructor(host: UmbControllerHostElement, args: UmbEntityBulkActionArgs<object>, action: string) {
		super(host, args);
		this.consumeContext(FORMS_FORM_WORKSPACE_CONTEXT, async (context) => {
			this.#workspaceContext = context;
		});

		this.consumeContext(UMB_COLLECTION_CONTEXT, (context) => {
			this.#collectionContext = context;
		});

		this.#action = action;
	}

	async execute() {
		const repository = new FormsFormEntryCollectionRepository(this._host);
		await repository.execute(this.#workspaceContext!.getUnique(), this.selection, this.#action);
		this.#collectionContext!.requestCollection();
	}
}
