import { UmbControllerBase } from "@umbraco-cms/backoffice/class-api";
import { UMB_MODAL_MANAGER_CONTEXT } from "@umbraco-cms/backoffice/modal";
import { FORMS_EXPORT_ENTRIES_MODAL } from "../../../../../modal/token/form-export-entries-modal.token.js";
import { FORMS_FORM_WORKSPACE_CONTEXT } from "../../../workspace/form-workspace.context-token.js";

export class FormsExportRecordsCollectionAction extends UmbControllerBase {
  async execute() {
    const workspaceContext = await this.getContext(
      FORMS_FORM_WORKSPACE_CONTEXT
    );

    const modalContext = await this.getContext(UMB_MODAL_MANAGER_CONTEXT);
    const modalHandler = modalContext.open(this, FORMS_EXPORT_ENTRIES_MODAL, {
      data: {
        unique: workspaceContext.getUnique(),
      },
    });

    await modalHandler.onSubmit().catch(() => undefined);
  }
}
