import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import type { UmbApi } from '@umbraco-cms/backoffice/extension-api';
import { UmbTreeRepositoryBase } from '@umbraco-cms/backoffice/tree';
import { FORMS_DATASOURCE_ROOT_ENTITY_TYPE } from '../entities.js';
import { FormsDataSourceTreeServerDataSource } from './datasources-tree.server.data-source.js';
import type { DataSourceTreeItemModel, DataSourceTreeRootModel } from './types.js';
import { FORMS_DATASOURCE_TREE_STORE_CONTEXT } from './datasources-tree.store.js';

export class FormsDataSourceTreeRepository
	extends UmbTreeRepositoryBase<DataSourceTreeItemModel, DataSourceTreeRootModel>
	implements UmbApi
{
	constructor(host: UmbControllerHost) {
		super(host, FormsDataSourceTreeServerDataSource, FORMS_DATASOURCE_TREE_STORE_CONTEXT);
	}

	async requestTreeRoot() {
		const data: DataSourceTreeRootModel = {
			unique: null,
			entityType: FORMS_DATASOURCE_ROOT_ENTITY_TYPE,
			name: 'Data Sources',
			hasChildren: true,
			isFolder: true,
		};

		return { data };
	}
}
