import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import type { UmbTreeAncestorsOfRequestArgs, UmbTreeChildrenOfRequestArgs, UmbTreeRootItemsRequestArgs} from "@umbraco-cms/backoffice/tree";
import { UmbTreeServerDataSourceBase } from "@umbraco-cms/backoffice/tree";
import type { DataSourceTreeItemResponseModel } from "@umbraco-forms/generated";
import { DataSourceService } from "@umbraco-forms/generated";
import { FORMS_DATASOURCE_ENTITY_TYPE, FORMS_DATASOURCE_ROOT_ENTITY_TYPE } from "../entities.js";
import type { DataSourceTreeItemModel } from "./types.js";

/**
 * A data source for the data sources tree that fetches data from the server
 * @export
 * @class FormsDataSourceTreeServerDataSource
 */
export class FormsDataSourceTreeServerDataSource extends UmbTreeServerDataSourceBase<
  DataSourceTreeItemResponseModel,
  DataSourceTreeItemModel
> {
  constructor(host: UmbControllerHost) {
    super(host, {
      getRootItems,
      getChildrenOf,
      getAncestorsOf,
      mapper,
    });
  }
}

// eslint-disable-next-line local-rules/no-direct-api-import
const getRootItems = (args: UmbTreeRootItemsRequestArgs) => DataSourceService.getTreeDataSourceRoot();

const getChildrenOf = (args: UmbTreeChildrenOfRequestArgs) => {
	if (args.parent.unique === null) {
		return getRootItems(args);
	} else {
		throw new Error('Not supported for the data source tree');
	}
};

const getAncestorsOf = (args: UmbTreeAncestorsOfRequestArgs) => {
	throw new Error('Not supported for the data source tree');
};

const mapper = (item: DataSourceTreeItemResponseModel): DataSourceTreeItemModel => {
  return {
    unique: item.id,
		parent: {
			unique: null,
			entityType: FORMS_DATASOURCE_ROOT_ENTITY_TYPE,
		},
    name: item.name,
    entityType: FORMS_DATASOURCE_ENTITY_TYPE,
    isFolder: item.isFolder,
    hasChildren: item.hasChildren,
  };
};
