import {
  css,
  customElement,
  html,
  unsafeHTML,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbModalBaseElement } from "@umbraco-cms/backoffice/modal";

const elementName = "forms-buy-license-modal";

@customElement(elementName)
export class FormsBuyLicenseModalElement extends UmbModalBaseElement {
  #submitModal() {
    window.open(
      "https://shop.umbraco.com/shop/cart/?p=6201&amp;direct=true&amp;utm_source=core&amp;utm_medium=dashboard&amp;utm_content=topic-link&amp;utm_campaign=formslicensing",
      "_blank"
    );
  }

  render() {
    return html`<umb-body-layout
      .headline=${this.localize.term("formsDashboard_buyLicenseTitle")}
    >
      ${unsafeHTML(this.localize.term("formsDashboard_buyLicenseCopy"))}
      <hr />
      ${unsafeHTML(this.localize.term("formsDashboard_buyLicenseFAQs"))}
      <div slot="actions">
        <uui-button
          label=${this.localize.term("general_close")}
          @click=${this._rejectModal}
        ></uui-button>
        <uui-button
          @click=${this.#submitModal}
          look="primary"
          color="positive"
          .label=${this.localize.term("formsDashboard_buyLink")}
        ></uui-button>
      </div>
    </umb-body-layout>`;
  }

  static styles = [
    css`
      :host {
        display: block;
        max-width: 80vw;
        width: 800px;
      }
    `,
  ];
}

export default FormsBuyLicenseModalElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsBuyLicenseModalElement;
  }
}
