import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { UmbDetailRepositoryBase } from "@umbraco-cms/backoffice/repository";
import { DataSourceService, type FormDataSource } from "@umbraco-forms/generated";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import {
  FORMS_DATASOURCE_DETAIL_STORE_CONTEXT,
} from "./datasource-detail.store.js";
import { FormsDataSourceDetailServerDataSource } from "./datasource-detail.server.data-source.js";

export class FormsDataSourceDetailRepository extends UmbDetailRepositoryBase<FormDataSource> {
  constructor(host: UmbControllerHost) {
    super(
      host,
      FormsDataSourceDetailServerDataSource,
      FORMS_DATASOURCE_DETAIL_STORE_CONTEXT
    );
  }

	async requestDataSourceScaffold() {
		const { data, error } = await tryExecuteAndNotify(this._host, DataSourceService.getDataSourceScaffold());

		if (error || !data) {
			return { error };
		}

		return { data };
	}

	async requestDataSourceWizardScaffold(id: string) {
		const { data, error } = await tryExecuteAndNotify(this._host, DataSourceService.getDatasourceWizardByIdScaffold({ id }));

		if (error || !data) {
			return { error };
		}

		return { data };
	}


}
