import { ThemeCollectionServerDataSource } from './theme-collection.server.data-source.js';
import type { UmbCollectionRepository } from '@umbraco-cms/backoffice/collection';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';

export class ThemeCollectionRepository implements UmbCollectionRepository {
	#collectionSource: ThemeCollectionServerDataSource;

	constructor(host: UmbControllerHost) {
		this.#collectionSource = new ThemeCollectionServerDataSource(host);
	}

	async requestCollection() {
		return this.#collectionSource.getCollection();
	}

	destroy(): void {}
}

export default ThemeCollectionRepository;
