import { UmbId } from "@umbraco-cms/backoffice/id";
import type { UmbDetailDataSource } from "@umbraco-cms/backoffice/repository";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import {
  type FormDataSource,
  DataSourceService,
} from "@umbraco-forms/generated";
import { FORMS_DATASOURCE_ENTITY_TYPE } from "../../entities.js";

/**
 * A data source for the Form that fetches data from the server
 * @export
 * @class FormsDataSourceDetailServerDataSource
 * @implements {RepositoryDetailDataSource}
 */
export class FormsDataSourceDetailServerDataSource
  implements UmbDetailDataSource<FormDataSource>
{
  #host: UmbControllerHost;

  constructor(host: UmbControllerHost) {
    this.#host = host;
  }

  /**
   * Creates a new data source scaffold
   * @param {(string | null)} parentUnique
   * @return { DataSourceDetailModel }
   * @memberof FormsDataSourceDetailServerDataSource
   */
  async createScaffold(preset: Partial<FormDataSource> = {}) {
    const data: FormDataSource = {
      entityType: FORMS_DATASOURCE_ENTITY_TYPE,
      unique: UmbId.new(),
      id: UmbId.new(),
      created: "",
      name: "",
      settings: {},
      formDataSourceTypeId: "",
      valid: false,
      updated: ""
    };

    return { data };
  }

  /**
   * Fetches a data source with the given id from the server
   * @param {string} unique
   * @return {FormDataSource}
   * @memberof FormsDataSourceDetailServerDataSource
   */
  async read(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    const { data, error } = await tryExecuteAndNotify(
      this.#host,
      DataSourceService.getDataSourceById({
        id: unique,
      })
    );

    if (error || !data) {
      return { error };
    }

    // TODO => this should be mapped, not cast
    return { data: data as FormDataSource };
  }

  /**
   * Inserts a new data source on the server
   * @param {FormDetailModel} form
   * @return {*}
   * @memberof FormsDataSourceDetailServerDataSource
   */
  async create(dataSource: FormDataSource) {
    if (!dataSource) throw new Error("Datasource is missing");
    if (!dataSource.unique) throw new Error("Datasource unique is missing");

    const { error: createError } = await tryExecuteAndNotify(
      this.#host,
      DataSourceService.postDataSource({
        requestBody: dataSource,
      })
    );

    if (createError) {
      return { error: createError };
    }

    // We have to fetch the data type again. The server can have modified the data after creation
    return this.read(dataSource.unique);
  }

  /**
   * Updates a data source on the server
   * @param {FormDetailModel} Form
   * @return {*}
   * @memberof FormsDataSourceDetailServerDataSource
   */
  async update(dataSource: FormDataSource) {
    if (!dataSource.unique) throw new Error("Unique is missing");

    const { error } = await tryExecuteAndNotify(
      this.#host,
      DataSourceService.putDataSourceById({
        id: dataSource.id,
        requestBody: dataSource,
      })
    );

    if (error) {
      return { error };
    }

    // We have to fetch the form again. The server can have modified the data after update
    return this.read(dataSource.unique);
  }

  /**
   * Deletes a data source on the server
   * @param {string} unique
   * @return {*}
   * @memberof FormsDataSourceDetailServerDataSource
   */
  async delete(unique: string) {
    if (!unique) throw new Error("Unique is missing");

    return tryExecuteAndNotify(
      this.#host,
      DataSourceService.deleteDataSourceById({
        id: unique,
      })
    );
  }
}
