import {
  property,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbLitElement } from "@umbraco-cms/backoffice/lit-element";
import type { FieldPrevalue } from '../../../generated/models.js';

export class FormsFieldPreviewBaseElement extends UmbLitElement {

  @property({ type: Array })
  prevalues: Array<FieldPrevalue> = [];

  @property()
  settings: Record<string, string> = {}

  getSettingValue(alias: string) : string {
    return this.settings[alias];
  }
}
