import {
  html,
  customElement,
} from "@umbraco-cms/backoffice/external/lit";
import { FormsFieldPreviewBaseElement } from './field-preview-base.element.js';

const elementName = "forms-field-preview-text-area"
@customElement(elementName)
export class FormsFieldPreviewTextArea extends FormsFieldPreviewBaseElement {

  render() {
    return html`<textarea
      rows="5"
      readonly
      disabled
      tabindex="-1"
      placeholder=${this.getSettingValue("Placeholder")}>${this.getSettingValue("DefaultValue")}</textarea>`;
  }
}

export default FormsFieldPreviewTextArea;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFieldPreviewTextArea;
  }
}
