import { customElement, html } from "@umbraco-cms/backoffice/external/lit";
import { FormsFieldPreviewBaseElement } from './field-preview-base.element.js';

const elementName = "forms-field-preview-dataconsent"
@customElement(elementName)
export class FormsFieldPreviewDataConsent extends FormsFieldPreviewBaseElement{
  render() {
    return html`<input type="checkbox" disabled tabindex="-1"/>
    <label>${this.getSettingValue("AcceptCopy")}</label>`;
  }
}

export default FormsFieldPreviewDataConsent;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFieldPreviewDataConsent;
  }
}
