import { UmbContextBase } from "@umbraco-cms/backoffice/class-api";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import { UmbObjectState } from "@umbraco-cms/backoffice/observable-api";
import type {
  BackOfficeConfig,
  FormSecurityForUser,
} from "@umbraco-forms/generated";
import { ConfigService, SecurityService } from "@umbraco-forms/generated";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { FORMS_CONTEXT } from './forms.context-token.js';
import { UMB_CURRENT_USER_CONTEXT } from "@umbraco-cms/backoffice/current-user";

export class FormsContext extends UmbContextBase<any> {
  #config = new UmbObjectState<BackOfficeConfig | undefined>(undefined);
  config = this.#config.asObservable();

  #userSecurity = new UmbObjectState<FormSecurityForUser | undefined>(
    undefined
  );
  userSecurity = this.#userSecurity.asObservable();

  constructor(host: UmbControllerHost) {
    super(host, FORMS_CONTEXT);
  }

  async hostConnected() {
    super.hostConnected();

    // Only load configuration and security details if the user has access to "forms" (as we only use it for functionality in there).
    this.consumeContext(UMB_CURRENT_USER_CONTEXT, (context) => {
      this.observe(context.currentUser, async (currentUser) => {
        const hasFormsAccess = currentUser?.allowedSections?.includes("Umb.Section.Forms") ?? false;
        if (hasFormsAccess) {
          this.#getConfig();
          this.getUserSecurity();
        }
      });
    });

  }

  async getUserSecurity() {
    const { data } = await tryExecuteAndNotify(
      this,
      SecurityService.getSecurityUserCurrentFormSecurity({
        includeFormFieldDetails: false,
      })
    );

    this.#userSecurity.setValue(data);
  }

  async #getConfig() {
    const { data } = await tryExecuteAndNotify(this, ConfigService.getConfig());

    this.#config.setValue(data);
  }
}

export default FormsContext;