import type { UmbCollectionRepository } from '@umbraco-cms/backoffice/collection';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import type { FormEntryCollectionFilterModel } from '../../types.js';
import { FormsFormEntryCollectionServerDataSource } from './entry-collection.server.data-source.js';
import { RecordSorting } from '@umbraco-forms/generated';

export class FormsFormEntryCollectionRepository implements UmbCollectionRepository {
  #collectionSource: FormsFormEntryCollectionServerDataSource;

  constructor(host: UmbControllerHost) {
    this.#collectionSource = new FormsFormEntryCollectionServerDataSource(host);
  }

  async requestCollection(filter: FormEntryCollectionFilterModel = {
    skip: 0,
    take: 10,
    formId: ''
  }) {
    // Set default sort if not provided.
    if (!filter.sortBy) {
      filter = { ...filter, ...{ sortBy: "created", sortOrder: RecordSorting.DESCENDING } };
    }

    return this.#collectionSource.getCollection(filter);
  }

  async execute(formId: string, recordIds: Array<string>, action: string) {
    return this.#collectionSource.execute(formId, recordIds, action);
  }

  destroy(): void {}
}

export default FormsFormEntryCollectionRepository;
