import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { umbExtensionsRegistry } from "@umbraco-cms/backoffice/extension-registry";
import { UmbLocalizationController } from '@umbraco-cms/backoffice/localization-api';
import type { UmbPropertyValueData } from "@umbraco-cms/backoffice/property";
import type { UmbPropertyEditorConfig } from "@umbraco-cms/backoffice/property-editor";
import type { ApiError, Setting } from "@umbraco-forms/generated";
import { loadManifestApi } from "@umbraco-cms/backoffice/extension-api";
import type { ManifestFormsSettingValueConverterPreview } from './setting-value-converters/setting-value-converter-preview.interface.js';
import type { FormsSettingValueConverterApi } from './setting-value-converters/setting-value-converter.interface.js';

export interface ProviderType {
  id: string;
  alias: string;
  settings: Array<Setting>;
}

export class ProviderTypeSettingsHelper {
  #host: UmbControllerHost;
  #localize: UmbLocalizationController;

  #providerType: ProviderType;
  #localizationSection: string;

  #settingValueConverterApis: Record<string, FormsSettingValueConverterApi> = {};

  constructor(host: UmbControllerHost, providerType: ProviderType, localizationSection: string) {
    this.#host = host;
    this.#localize = new UmbLocalizationController(this.#host);

    this.#providerType = providerType;
    this.#localizationSection = localizationSection;
  }

  async loadSettingValueConverterApis() {
		const settingValueConverters = umbExtensionsRegistry.getAllExtensions()
      .filter(e => e.type === "formsSettingValueConverter")
      .map(mt => mt as ManifestFormsSettingValueConverterPreview);

    for (let i = 0; i < settingValueConverters.length; i++) {
      const settingValueConverter = settingValueConverters[i];
      const api = await loadManifestApi(settingValueConverter.api);
      if (api) {
        const apiInstance = new api() as FormsSettingValueConverterApi;
        if (apiInstance) {
          this.#settingValueConverterApis[settingValueConverter.propertyEditorUiAlias] = apiInstance;
        }
      }
    }
  }

  setProviderType(providerType: ProviderType) {
    this.#providerType = providerType;
  }

  getLocalizedSettingDetail(setting: Setting, detail: string, defaultValue: string) {
    const key =
      this.#localizationSection +
      "_" +
      this.#providerType.alias +
      setting.alias +
      detail;
    const value = this.#localize.term(key);

    // If we don't have a localized value, return the hardcoded value provided by the Setting attribute's properties.
    if (value && value.length > 0 && value !== key) {
      return value;
    }

    return defaultValue;
  }

  async getSettingValues(settings: Record<string, string>) {
    const settingValues: Array<UmbPropertyValueData> = [];
    for (const [alias, value] of Object.entries(settings)) {
      const settingValue = await this.#getSettingValueForEditor(alias, value);
      settingValues.push({ alias, value: settingValue  });
    }
    return settingValues;
  }

  async getSettingsConfig(
    settingValues: Array<UmbPropertyValueData>,
    typeSettings: Array<Setting>
  ) {
    const config: Array<{
      alias: string;
      value: UmbPropertyEditorConfig;
    }> = [];
    for (const s of settingValues) {
      await this.#addSettingToConfig(config, s.alias, settingValues);
    }

    // If we have a setting added since the value was saved, or just a new item without settings, we need to add empty
    // values to the configuration.
    for (const s of typeSettings) {
      if (config.find((c) => c.alias === s.alias)) continue;
      await this.#addSettingToConfig(config, s.alias, []);
    }

    return config;
  }

  async #addSettingToConfig(
    config: Array<{
      alias: string;
      value: UmbPropertyEditorConfig;
    }>,
    alias: string,
    settingValues: Array<UmbPropertyValueData>
  ) {
    config.push({
      alias: alias,
      value: await this.getSettingPropertyConfig(alias, settingValues),
    });
  }

  async getSettingPropertyConfig(alias: string, values: Array<UmbPropertyValueData>) {
    const setting = this.#getSettingByAlias(alias);
    if (!setting) {
      return [];
    }

    const settingValueConverterApi = this.#getSettingValueConverterApi(setting.view);
    if (settingValueConverterApi) {
      return await settingValueConverterApi.getSettingPropertyConfig(setting, alias, values);
    }

    return [];
  }

  #getSettingValueConverterApi(settingView: string) {
    return this.#settingValueConverterApis[settingView];
  }

  async getUpdatedSettingsForPersistence(value: Array<UmbPropertyValueData>, typeSettings?: Array<Setting>) {
    // filter the settings values to keep those with non-default values
    if (typeSettings) {
      const typeSettingsMap = Object.fromEntries(typeSettings.map((s) => [s.alias, s.defaultValue]));
      value = value.filter(v => v.value !== typeSettingsMap[v.alias]);
    }

    const settings = {};
    for (let i = 0; i < value.length; i++) {
      const item = value[i];
      settings[item.alias] = await this.#getSettingValueForPersistence(item);
    }

    return settings;
  }

  async #getSettingValueForEditor(alias: string, value: string) {
    // Transform the string value into the type appropriate for the property editor.
    const setting = this.#getSettingByAlias(alias);
    if (!setting) {
      return null;
    }

    const settingValueConverterApi = this.#getSettingValueConverterApi(setting.view);
    if (settingValueConverterApi) {
      return await settingValueConverterApi.getSettingValueForEditor(setting, alias, value);
    }

    return value;
  }

  #getSettingByAlias(alias: string) {
    return this.#providerType.settings.find((s) => s.alias === alias);
  }

  async #getSettingValueForPersistence(valueData: UmbPropertyValueData) {
    // Transform the editor value back into a string for persistence.
    const setting = this.#getSettingByAlias(valueData.alias);
    if (!setting) {
      return "";
    }

    const settingValueConverterApi = this.#getSettingValueConverterApi(setting.view);
    if (settingValueConverterApi) {
      return await settingValueConverterApi.getSettingValueForPersistence(setting, valueData);
    }

    return valueData.value;
  }

  createValidationErrorNotification(headlineKey: string, error: ApiError) {
    const errorMessages = error.body!["detail"].split("|").join(", ");
    const notification = {
      data: {
        headline: this.#localize.term(headlineKey),
        message: errorMessages,
      },
    };
    return notification;
  }

  getPropertyConfigForSetting(settingsConfig: Array<{ alias: string; value: UmbPropertyEditorConfig }>, setting: Setting) {
    return settingsConfig.find((c) => c.alias === setting.alias)?.value ?? [];
  }

  getPropertyAppearanceForSetting(view: string) {
    return view === "Umb.PropertyEditorUi.Tiptap" ? { labelOnTop: true} : undefined;
  }
}
