import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import type { UmbTreeAncestorsOfRequestArgs, UmbTreeChildrenOfRequestArgs, UmbTreeRootItemsRequestArgs} from "@umbraco-cms/backoffice/tree";
import { UmbTreeServerDataSourceBase } from "@umbraco-cms/backoffice/tree";
import type { SecurityTreeItemResponseModel } from "@umbraco-forms/generated";
import { SecurityService } from "@umbraco-forms/generated";
import { FORMS_SECURITY_USER_FOLDER_ENTITY_TYPE, FORMS_SECURITY_USER_GROUP_FOLDER_ENTITY_TYPE, FORMS_SECURITY_USER_ENTITY_TYPE, FORMS_SECURITY_USER_GROUP_ENTITY_TYPE } from "../entities.js";
import type { SecurityTreeItemModel } from "./types.js";

export class FormsSecurityTreeServerDataSource extends UmbTreeServerDataSourceBase<
  SecurityTreeItemResponseModel,
  SecurityTreeItemModel
> {
  constructor(host: UmbControllerHost) {
    super(host, {
      getRootItems,
      getChildrenOf,
      getAncestorsOf,
      mapper,
    });
  }
}

const getRootItems = (args: UmbTreeRootItemsRequestArgs) => SecurityService.getTreeSecurityRoot();

const getChildrenOf = (args: UmbTreeChildrenOfRequestArgs) => {
  if (args.parent.unique === null) {
    return getRootItems(args);
  }
  return SecurityService.getTreeSecurityChildrenByParentId({
    parentId: args.parent.unique
  });
};

const getAncestorsOf = (args: UmbTreeAncestorsOfRequestArgs) => {
	throw new Error('Not supported for the security tree');
};

const mapper = (item: SecurityTreeItemResponseModel): SecurityTreeItemModel => {
  return {
    unique: item.id,
    parent: { unique: item.parent?.id || "", entityType: "" },
    name: item.name,
    entityType: item.isFolder
      ? item.id === "207c2294-970b-4e1f-82fd-ae8996ef171d" // Matches FormBuilderWeb.Controllers.ManagementApi.Security.Tree.SecurityTreeControllerBase.UsersFolderId
        ? FORMS_SECURITY_USER_FOLDER_ENTITY_TYPE
        : FORMS_SECURITY_USER_GROUP_FOLDER_ENTITY_TYPE
      : item.isGroup
        ? FORMS_SECURITY_USER_GROUP_ENTITY_TYPE
        : FORMS_SECURITY_USER_ENTITY_TYPE,
    isFolder: item.isFolder,
    hasChildren: item.hasChildren,
  };
};
