import {
  html,
  customElement,
} from "@umbraco-cms/backoffice/external/lit";
import { FormsFieldPreviewBaseElement } from './field-preview-base.element.js';

const elementName = "forms-field-preview-text-box"
@customElement(elementName)
export class FormsFieldPreviewTextBox extends FormsFieldPreviewBaseElement {

  render() {
    return html`<input
      type="${this.getSettingValue("FieldType") || "text"}"
      readonly
      disabled
      tabindex="-1"
      placeholder="${this.getSettingValue("Placeholder")}"
      value="${this.getSettingValue("DefaultValue")}" />`;
  }
}

export default FormsFieldPreviewTextBox;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFieldPreviewTextBox;
  }
}
