import { customElement, html } from "@umbraco-cms/backoffice/external/lit";
import { FormsFieldPreviewBaseElement } from './field-preview-base.element.js';

const elementName = "forms-field-preview-hiddenfield"
@customElement(elementName)
export class FormsFieldPreviewHiddenField extends FormsFieldPreviewBaseElement{
  render() {
    return html`<input disabled type="hidden" />`;
  }
}

export default FormsFieldPreviewHiddenField;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFieldPreviewHiddenField;
  }
}
