import type { UmbPropertyValueData } from "@umbraco-cms/backoffice/property";
import type { Setting } from "@umbraco-forms/generated";
import type { FormsSettingValueConverterApi } from './setting-value-converter.interface.js';

export class FormsSourcePickerSettingValueConverter
  implements FormsSettingValueConverterApi
{
  async getSettingValueForEditor(setting: Setting, alias: string, value: string) {
    if (value.length === 0) {
      return Promise.resolve({});
    }

    return Promise.resolve(JSON.parse(value));
  }

  async getSettingValueForPersistence(setting: Setting, valueData: UmbPropertyValueData) {
    return Promise.resolve(JSON.stringify(valueData.value));
  }

  async getSettingPropertyConfig(
    setting: Setting,
    alias: string,
    values: UmbPropertyValueData[]
  ) {
    return Promise.resolve([]);
  }

  destroy() {}
}
