import {
  html,
  customElement,
  property,
  when,
  css,
} from "@umbraco-cms/backoffice/external/lit";
import { type FormWorkflows } from "@umbraco-forms/generated";
import { FORMS_CONFIGURE_WORKFLOW_MODAL } from "@umbraco-forms/modals";
import type { SubmitMessageDetail } from "../types.js";
import { FormsFormDesignElementBaseElement } from "./forms-design-element-base.element.js";

const elementName = "forms-form-workflow-summary";

@customElement(elementName)
export class FormsFormWorkflowSummaryElement extends FormsFormDesignElementBaseElement {
  @property({ type: Object })
  workflows?: FormWorkflows;

  @property({ type: Object })
  submitMessageDetail?: SubmitMessageDetail;

  @property({ type: Boolean })
  manualApproval: boolean = false;

  #onConfigureWorkflowClick() {
    if (!this.modalContext) return;

    const modalHandler = this.modalContext.open(
      this,
      FORMS_CONFIGURE_WORKFLOW_MODAL,
      {
        data: {
          manualApproval: this.manualApproval,
          fields: this.allFields,
        },
        value: {
          workflows: this.workflows,
          submitMessageDetail: this.submitMessageDetail,
        },
      }
    );

    modalHandler.onSubmit().then((value) => {
      if (value.submitMessageDetail) {
        this.workspaceContext!.setFormProperty(
          "messageOnSubmit",
          value.submitMessageDetail.messageOnSubmit
        );
        this.workspaceContext!.setFormProperty(
          "messageOnSubmitIsHtml",
          value.submitMessageDetail.messageOnSubmitIsHtml
        );
        this.workspaceContext!.setFormProperty(
          "goToPageOnSubmit",
          value.submitMessageDetail.goToPageOnSubmit
        );
      }

      if (value.workflows) {
        this.workspaceContext!.setFormProperty(
          "formWorkflows",
          value.workflows
        );
      }
    }).catch(() => undefined);
  }

  render() {
    return html`<uui-box>
      <div class="flex">
        <div>
          <forms-form-workflow-summary-stage
            .workflows=${this.workflows?.onSubmit ?? []}
            .submitMessageDetail=${this.submitMessageDetail}
            .allFields=${this.allFields}
            .label=${this.localize.term("formWorkflows_onSubmit")}
            collectionName="onSubmit"
            icon="icon-check"
          ></forms-form-workflow-summary-stage>
          ${when(
            (this.workflows?.onApprove ?? []).length > 0,
            () => html`<forms-form-workflow-summary-stage
              .workflows=${this.workflows?.onApprove ?? []}
              .allFields=${this.allFields}
              .label=${this.localize.term("formWorkflows_onApprove") +
              (this.manualApproval
                ? " (" + this.localize.term("formWorkflows_automatic") + ")"
                : "")}
              collectionName="onApprove"
              icon="icon-thumb-up"
            ></forms-form-workflow-summary-stage>`
          )}
          ${when(
            this.manualApproval && (this.workflows?.onReject ?? []).length > 0,
            () => html`<forms-form-workflow-summary-stage
              .workflows=${this.workflows?.onReject ?? []}
              .allFields=${this.allFields}
              .label=${this.localize.term("formWorkflows_onReject")}
              collectionName="onReject"
              icon="icon-delete"
            ></forms-form-workflow-summary-stage>`
          )}
        </div>
        <uui-button
          @click=${this.#onConfigureWorkflowClick}
          look="secondary"
          label=${this.localize.term("formWorkflows_configureWorkflow")}
        ></uui-button>
      </div>
    </uui-box>`;
  }

  static styles = [
    css`
      .flex {
        display: flex;
        column-gap: var(--uui-size-5);
      }

      .flex > div:first-child {
        flex: 1;
      }

      uui-button {
        align-self:center;
      }

      forms-form-workflow-summary-stage + forms-form-workflow-summary-stage {
        margin-top: var(--uui-size-5);
      }
    `,
  ];
}

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFormWorkflowSummaryElement;
  }
}
