import {
  css,
  customElement,
  html,
  state,
  unsafeHTML,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import { UUIInputEvent } from "@umbraco-cms/backoffice/external/uui";
import { UmbModalBaseElement } from "@umbraco-cms/backoffice/modal";
import { UMB_NOTIFICATION_CONTEXT } from "@umbraco-cms/backoffice/notification";
import { tryExecute, tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import type { License, LicenseConfiguration } from "@umbraco-forms/generated";
import { LicensingService } from "@umbraco-forms/generated";

const elementName = "forms-configure-license-modal";

@customElement(elementName)
export class FormsConfigureLicenseModalElement extends UmbModalBaseElement {

  #notificationContext?: typeof UMB_NOTIFICATION_CONTEXT.TYPE;

  @state()
  private _isLoading = false;

  @state()
  private _hasLicenses?: boolean;

  @state()
  private _loginError = false;

  @state()
  private _configuration: LicenseConfiguration = {
    domain: window.location.hostname,
    email: "",
    password: "",
    license: "",
  };

  @state()
  private _configuredLicenses: Array<License> = [];

  @state()
  private _openLicenses: Array<License> = [];

  @state()
  private _selectedLicense?: License;

  constructor() {
    super();

    this.consumeContext(UMB_NOTIFICATION_CONTEXT, (instance) => {
      this.#notificationContext = instance;
    });
  }

  #onEmailChange(e: UUIInputEvent) {
    if (!this._configuration) return;
    this._configuration.email = e.target.value.toString();
  }

  #onPasswordChange(e: UUIInputEvent) {
    if (!this._configuration) return;
    this._configuration.password = e.target.value.toString();
  }

  async #configureLicense() {
    this._isLoading = true;

    const { error } = await tryExecute(LicensingService.postLicensingConfigure({
      requestBody: this._configuration,
    }));
    if (error) {
      this.#notificationContext?.peek("danger", {
        data: { message: "An error occurred configuring the license." },
      });
    } else {
      this.#notificationContext?.peek("positive", {
        data: { message: this.localize.term("formsDashboard_licenseConfiguredNotificationTitle") },
      });
      this._submitModal();
    }
  }

  async #getLicenses() {
    this._loginError = false;
    this._hasLicenses = undefined;
    this._isLoading = true;

		const { data } = await tryExecuteAndNotify(
      this,
			LicensingService.postLicensingAvailable({
        requestBody: this._configuration,
      }));

    if (data) {

      this._hasLicenses = data.length > 0;
      this._configuredLicenses = data
        .filter((lic) => lic.configured)
        .sort(
          (a, b) =>
            Number(a.bindings.includes(this._configuration.domain)) -
            Number(b.bindings.includes(this._configuration.domain))
        );

      this._openLicenses = data.filter((lic) => !lic.configured);

      if (!this._hasLicenses) {
        this.#notificationContext?.peek("danger", {
          data: { message: "No licenses could be retrieved with the provided credentials." },
        });
      }
    }

    this._isLoading = false;
  }

  #selectLicense(license: License) {
    this._configuration.license = license.id;
    this._selectedLicense = license;
  }

  #renderConfigureLicenseButton(labelKey: string) {
    return html`
      <uui-button
        look="primary"
        color="positive"
        @click=${this.#configureLicense}
        .label=${this.localize.term(labelKey)}
      ></uui-button>
    `;
  }

  #renderSelectLicenseButton(license: License) {
    return html`<uui-button
      look="primary"
      color="positive"
      @click=${() => this.#selectLicense(license)}
      .label=${license.label}
    ></uui-button>`;
  }

  #renderAlertIcon(labelKey: string) {
    return html`<span class="alert"
      ><uui-icon name="icon-alert"></uui-icon> ${this.localize.term(
        labelKey
      )}</span
    >`;
  }

  render() {
    return html`<umb-body-layout
      .headline=${this.localize.term("formsDashboard_configureLicenseTitle")}
    >
      <p>${this.localize.term("formsDashboard_configureLicenseCopy")}</p>

      ${when(this._isLoading, () => html`<uui-loader></uui-loader>`)}
      ${when(
        !this._isLoading && !this._hasLicenses,
        () => html`<p>
            <strong>${this.localize.term("general_email")}:</strong><br />
            <uui-input
              label="email"
              .value=${this._configuration?.email}
              @change=${this.#onEmailChange}
            ></uui-input
            ><br />
            <strong>${this.localize.term("general_password")}:</strong><br />
            <uui-input
              type="password"
              label="password"
              .value=${this._configuration?.password}
              @change=${this.#onPasswordChange}
              spellcheck="false"
            ></uui-input
            ><br />
            <uui-button
              look="primary"
              color="positive"
              @click=${this.#getLicenses}
              .label=${this.localize.term("formsDashboard_findLicenses")}
            ></uui-button>

            ${when(this._loginError, () =>
              this.#renderAlertIcon("formsDashboard_invalidEmail")
            )}
            ${when(!this._hasLicenses === false, () =>
              this.#renderAlertIcon("formsDashboard_noLicensesAvailable")
            )}
          </p>
          <hr />
          ${unsafeHTML(
            this.localize.term("formsDashboard_configureLicenseFAQs")
          )}`
      )}
      ${when(
        this._hasLicenses,
        () => html` <h5>
            ${this.localize.term("formsDashboard_availableLicensesTitle")}
          </h5>
          <p>
            ${this.localize.term("formsDashboard_foundLicenses")}
            <strong
              >${this._openLicenses.length +
              this._configuredLicenses.length}</strong
            >
            ${this.localize.term("formsDashboard_foundLicensesAccount")}
            <strong>${this._configuration.email}}</strong>
          </p>
          ${when(
            this._openLicenses.length,
            () => html`
              <ul>
                ${this._openLicenses.map(
                  (lic) => html`<li style="max-width:600px">
                    <uui-icon name="icon-certificate"></uui-icon>
                    ${this.#renderSelectLicenseButton(lic)}
                    <small
                      >${this.localize.term(
                        "formsDashboard_noDomainsAssigned"
                      )}</small
                    >
                    ${when(
                      lic === this._selectedLicense,
                      () => html`<p>
                          ${this.localize.term("formsDashboard_setDomain")}:
                        </p>
                        <uui-input
                          label="domain"
                          value=${this._configuration.domain}
                        ></uui-input>
                        ${this.#renderConfigureLicenseButton(
                          "formsDashboard_configureAndInstall"
                        )} `
                    )}
                  </li>`
                )}
              </ul>
              <hr />
            `
          )}

          <ul>
            ${this._configuredLicenses.map(
              (lic) =>
                html`<li>
                  <uui-icon name="icon-certificate"></uui-icon>
                  ${this.#renderSelectLicenseButton(lic)}
                  <small>
                    ${when(
                      lic.bindings.includes(this._configuration.domain),
                      () => html` <uui-icon
                        name="icon-check"
                        title=${this.localize.term(
                          "formsDashboard_licenseValidOnDomain"
                        )}
                      ></uui-icon>`,
                      () =>
                        this.#renderAlertIcon(
                          "formsDashboard_licenseNotValidOnDomain"
                        )
                    )}
                    ${this.localize.term("formsDashboard_validDomains")}:
                    ${lic.bindings.join()}
                  </small>

                  ${when(lic === this._selectedLicense, () =>
                    this.#renderConfigureLicenseButton(
                      "formsDashboard_installLicense"
                    )
                  )}
                </li>`
            )}
          </ul>`
      )}
      <div slot="actions">
        <uui-button
          label=${this.localize.term("general_close")}
          @click=${this._rejectModal}
        ></uui-button>
      </div>
    </umb-body-layout>`;
  }

  static styles = [
    css`
      :host {
        display: block;
        max-width: 80vw;
        width: 800px;
      }
      .alert {
        display: flex;
        align-items: center;
        background: var(--uui-color-danger);
        border-radius: var(--uui-border-radius);
        color: var(--uui-color-danger-contrast);
        padding: var(--uui-size-3);
        margin-top: var(--uui-size-5);
      }

      uui-button {
        margin-top: var(--uui-size-3);
      }

      .alert uui-icon {
        margin-right: var(--uui-size-3);
      }
    `,
  ];
}

export default FormsConfigureLicenseModalElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsConfigureLicenseModalElement;
  }
}
